import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { cn } from "@/lib/utils";

export type FloatingNavbarVariant = "pill" | "underline" | "block";

interface NavItem {
  label: string;
  href: string;
}

interface FloatingNavbarProps {
  items?: NavItem[];
  className?: string;
  color?: string;
  speed?: number;
  scale?: number;
  variant?: FloatingNavbarVariant;
}

const defaultItems = [
  { label: "Home", href: "#" },
  { label: "Showcase", href: "#" },
  { label: "Specs", href: "#" },
];

export function FloatingNavbar({
  items,
  className,
  color,
  speed = 1,
  scale = 1,
  variant = "pill",
}: FloatingNavbarProps) {
  const [hoveredIndex, setHoveredIndex] = useState<number | null>(null);
  const [isVisible, setIsVisible] = useState(true);
  const [lastScrollY, setLastScrollY] = useState(0);

  const navItems = items && items.length > 0 ? items : defaultItems;

  useEffect(() => {
    const handleScroll = () => {
      const currentScrollY = window.scrollY;
      if (currentScrollY > lastScrollY && currentScrollY > 100) {
        setIsVisible(false); // Hide on scroll down
      } else {
        setIsVisible(true); // Show on scroll up
      }
      setLastScrollY(currentScrollY);
    };

    window.addEventListener("scroll", handleScroll, { passive: true });
    return () => window.removeEventListener("scroll", handleScroll);
  }, [lastScrollY]);

  const hasPosition =
    className?.includes("absolute") ||
    className?.includes("relative") ||
    className?.includes("fixed");

  const activeStiffness = 350 * speed;
  const activeDamping = 25 / speed;

  return (
    <AnimatePresence>
      {isVisible && (
        <motion.nav
          initial={{ y: -100, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          exit={{ y: -100, opacity: 0 }}
          transition={{ duration: 0.35 / speed, ease: [0.16, 1, 0.3, 1] }}
          className={cn(
            "z-50 flex items-center justify-between rounded-full border border-border bg-background/80 backdrop-blur-xl shadow-2xl transition-colors duration-300",
            variant === "underline" ? "px-6 py-2" : "p-2",
            !hasPosition && "fixed top-6 left-1/2 -translate-x-1/2",
            className
          )}
          style={{
            transform: scale !== 1 ? `scale(${scale})` : undefined,
          }}
        >
          <div className={cn("flex items-center", variant === "underline" ? "gap-6" : "gap-1.5")}>
            {navItems.map((item, idx) => (
              <a
                key={idx}
                href={item.href}
                onMouseEnter={() => setHoveredIndex(idx)}
                onMouseLeave={() => setHoveredIndex(null)}
                className={cn(
                  "relative transition-colors",
                  variant === "underline" ? "py-2 text-sm" : "px-4 py-2 rounded-full text-xs",
                  "font-medium text-muted-foreground hover:text-foreground"
                )}
              >
                {hoveredIndex === idx && (
                  <motion.span
                    layoutId={`navHover-${variant}`}
                    className={cn(
                      "absolute -z-10",
                      variant === "underline"
                        ? "bottom-0 left-0 right-0 h-[2px] bg-foreground rounded-full"
                        : variant === "block"
                        ? "inset-0 bg-foreground rounded-full"
                        : "inset-0 bg-muted border border-border/50 rounded-full" // default pill
                    )}
                    style={
                      variant === "underline"
                        ? { backgroundColor: color || "currentColor" }
                        : variant === "block"
                        ? { backgroundColor: color ? `${color}30` : undefined }
                        : {
                            backgroundColor: color ? `${color}15` : undefined,
                            borderColor: color ? `${color}40` : undefined,
                          }
                    }
                    transition={{ type: "spring", stiffness: activeStiffness, damping: activeDamping }}
                  />
                )}
                {item.label}
              </a>
            ))}
          </div>
        </motion.nav>
      )}
    </AnimatePresence>
  );
}

"use client";

import React, { useEffect, useRef, useState, useMemo } from "react";
import { motion, motionValue } from "framer-motion";
import Matter from "matter-js";
import { cn } from "@/lib/utils";

interface PhysicsDockProps {
  children: React.ReactNode;
  className?: string;
  itemClassName?: string;
  /** Radius of the collision body for each icon */
  itemRadius?: number;
  /** Spacing between items */
  gap?: number;
  /** Spring stiffness holding items to their anchor */
  stiffness?: number;
  /** Spring damping */
  damping?: number;
  /** How much items repel each other (collision bounciness) */
  bounciness?: number;
  /** Shape of the physics body */
  bodyType?: "circle" | "rectangle";
}

export function PhysicsDock({
  children,
  className,
  itemClassName,
  itemRadius = 24,
  gap = 12,
  stiffness = 0.05,
  damping = 0.1,
  bounciness = 0.4,
  bodyType = "circle",
}: PhysicsDockProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const engineRef = useRef<Matter.Engine | null>(null);
  const renderRef = useRef<Matter.Render | null>(null);

  const items = React.Children.toArray(children);
  const numItems = items.length;

  // We need motion values for each item
  const motionValues = useMemo(() => {
    return items.map(() => ({
      x: motionValue(0),
      y: motionValue(0),
      rotate: motionValue(0),
    }));
  }, [items.length]);

  useEffect(() => {
    if (!containerRef.current) return;
    const container = containerRef.current;

    // Setup Matter.js Engine
    const engine = Matter.Engine.create();
    engineRef.current = engine;

    // We want a top-down view without gravity pulling them to the bottom of the screen.
    // The springs will hold them in place.
    engine.world.gravity.y = 0;
    engine.world.gravity.x = 0;

    const width = container.clientWidth;
    const height = container.clientHeight;

    // Optional: add visual debugger rendering (commented out for prod)
    /*
    const render = Matter.Render.create({
      element: container,
      engine: engine,
      options: {
        width,
        height,
        wireframes: false,
        background: 'transparent'
      }
    });
    renderRef.current = render;
    Matter.Render.run(render);
    */

    // Calculate anchor positions
    // We want them centered in the container.
    const totalWidth = (itemRadius * 2 * numItems) + (gap * (numItems - 1));
    const startX = (width - totalWidth) / 2 + itemRadius;
    const centerY = height / 2;

    const bodies: Matter.Body[] = [];
    const constraints: Matter.Constraint[] = [];

    // Create a bounding box so items don't fly off screen
    const wallOptions = { isStatic: true, render: { visible: false } };
    const wallThickness = 100;
    Matter.World.add(engine.world, [
      Matter.Bodies.rectangle(width / 2, -wallThickness / 2, width + wallThickness * 2, wallThickness, wallOptions), // Top
      Matter.Bodies.rectangle(width / 2, height + wallThickness / 2, width + wallThickness * 2, wallThickness, wallOptions), // Bottom
      Matter.Bodies.rectangle(-wallThickness / 2, height / 2, wallThickness, height + wallThickness * 2, wallOptions), // Left
      Matter.Bodies.rectangle(width + wallThickness / 2, height / 2, wallThickness, height + wallThickness * 2, wallOptions), // Right
    ]);

    items.forEach((_, i) => {
      const x = startX + i * (itemRadius * 2 + gap);
      const y = centerY;

      const bodyOptions = {
        restitution: bounciness, // Bounciness
        frictionAir: 0.1, // Air resistance to calm them down
        friction: 0.1,
        density: 0.05,
      };

      const body = bodyType === "circle" 
        ? Matter.Bodies.circle(x, y, itemRadius, bodyOptions)
        : Matter.Bodies.rectangle(x, y, itemRadius * 2, itemRadius * 2, {
            ...bodyOptions,
            chamfer: { radius: 12 } // slightly rounded corners for the physics body to prevent sticking
          });

      // Anchor constraint (Spring)
      const constraint = Matter.Constraint.create({
        pointA: { x, y }, // The anchor point in the world
        bodyB: body,      // The body to attach
        pointB: { x: 0, y: 0 },
        stiffness: stiffness,
        damping: damping,
        render: { visible: false }
      });

      bodies.push(body);
      constraints.push(constraint);

      // Initialize motion values
      motionValues[i].x.set(x);
      motionValues[i].y.set(y);
    });

    Matter.World.add(engine.world, [...bodies, ...constraints]);

    // Add Mouse interaction
    const mouse = Matter.Mouse.create(container);
    const mouseConstraint = Matter.MouseConstraint.create(engine, {
      mouse: mouse,
      constraint: {
        stiffness: 0.2,
        render: { visible: false },
      },
    });

    // Fix mouse wheel scrolling issue on the container
    mouseConstraint.mouse.element.removeEventListener("mousewheel", (mouseConstraint.mouse as any).mousewheel);
    mouseConstraint.mouse.element.removeEventListener("DOMMouseScroll", (mouseConstraint.mouse as any).mousewheel);

    Matter.World.add(engine.world, mouseConstraint);

    // Sync physics to Framer Motion
    Matter.Events.on(engine, "afterUpdate", () => {
      bodies.forEach((body, i) => {
        motionValues[i].x.set(body.position.x);
        motionValues[i].y.set(body.position.y);
        motionValues[i].rotate.set(body.angle * (180 / Math.PI));
      });
    });

    // Start Runner
    const runner = Matter.Runner.create();
    Matter.Runner.run(runner, engine);

    // Handle Resize (Re-center anchors)
    const handleResize = () => {
      const newWidth = container.clientWidth;
      const newHeight = container.clientHeight;
      const newStartX = (newWidth - totalWidth) / 2 + itemRadius;
      const newCenterY = newHeight / 2;

      constraints.forEach((c, i) => {
        c.pointA = { x: newStartX + i * (itemRadius * 2 + gap), y: newCenterY };
      });

      // Update mouse scale if needed (usually handled by matter-js, but good to be aware)
    };

    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      Matter.Runner.stop(runner);
      if (renderRef.current) {
        Matter.Render.stop(renderRef.current);
        renderRef.current.canvas.remove();
      }
      Matter.Engine.clear(engine);
      Matter.World.clear(engine.world, false);
    };
  }, [items.length, itemRadius, gap, stiffness, damping, bounciness, bodyType, motionValues]);

  return (
    <div 
      ref={containerRef} 
      className={cn("relative w-full h-[200px] overflow-hidden rounded-2xl", className)}
    >
      {/* 
        Matter.js will handle pointer events via its MouseConstraint attached to this container. 
        We just render the elements at the motion values.
      */}
      {items.map((child, i) => (
        <motion.div
          key={i}
          className={cn("absolute top-0 left-0 flex items-center justify-center cursor-grab active:cursor-grabbing", itemClassName)}
          style={{
            width: itemRadius * 2,
            height: itemRadius * 2,
            x: motionValues[i].x,
            y: motionValues[i].y,
            rotate: motionValues[i].rotate,
            // We use -marginLeft/Top to center the DOM element on the physics body's center (which is its x,y)
            marginLeft: -itemRadius,
            marginTop: -itemRadius,
          }}
          // Prevent standard drag so Matter.js can take over
          onDragStart={(e) => e.preventDefault()}
        >
          {child}
        </motion.div>
      ))}
    </div>
  );
}

"use client";

import React, { useEffect, useState, useRef, useCallback } from "react";
import { Command } from "cmdk";
import { DialogTitle, DialogDescription } from "@radix-ui/react-dialog";
import { cn } from "@/lib/utils";
import { TerminalSquare } from "lucide-react";

export interface CyberTerminalProps {
  /** Array of commands to display */
  commands: {
    heading: string;
    items: {
      id: string;
      title: string;
      icon?: React.ReactNode;
      onSelect: () => void;
    }[];
  }[];
  /** Whether the terminal is open */
  open: boolean;
  /** Function to change open state */
  onOpenChange: (open: boolean) => void;
  /** Whether typing sounds are enabled */
  soundEnabled?: boolean;
  /** Optional class name */
  className?: string;
}

export function CyberTerminal({
  commands,
  open,
  onOpenChange,
  soundEnabled = true,
  className,
}: CyberTerminalProps) {
  const [inputValue, setInputValue] = useState("");
  const audioContextRef = useRef<AudioContext | null>(null);

  // Initialize Web Audio API on first interaction (required by browsers)
  const initAudio = useCallback(() => {
    if (!audioContextRef.current && soundEnabled) {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      if (AudioContext) {
        audioContextRef.current = new AudioContext();
      }
    }
  }, [soundEnabled]);

  // Play synthetic mechanical keystroke
  const playKeystroke = useCallback(() => {
    if (!soundEnabled || !audioContextRef.current) return;
    const ctx = audioContextRef.current;

    // Resume context if suspended
    if (ctx.state === "suspended") ctx.resume();

    // Create a very short, high-pitched mechanical "click"
    const osc = ctx.createOscillator();
    const gainNode = ctx.createGain();

    osc.type = "square";
    // Randomize frequency slightly for organic feel
    osc.frequency.setValueAtTime(150 + Math.random() * 50, ctx.currentTime);

    // Very sharp envelope
    gainNode.gain.setValueAtTime(0, ctx.currentTime);
    gainNode.gain.linearRampToValueAtTime(0.05, ctx.currentTime + 0.002);
    gainNode.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.02);

    osc.connect(gainNode);
    gainNode.connect(ctx.destination);

    osc.start();
    osc.stop(ctx.currentTime + 0.02);
  }, [soundEnabled]);

  // Handle keyboard shortcut (CMD+K)
  useEffect(() => {
    const down = (e: KeyboardEvent) => {
      if (e.key === "k" && (e.metaKey || e.ctrlKey)) {
        e.preventDefault();
        onOpenChange(!open);
      }
    };
    document.addEventListener("keydown", down);
    return () => document.removeEventListener("keydown", down);
  }, [open, onOpenChange]);

  // Matrix scramble effect for selected items
  const handleSelect = (onSelectAction: () => void) => {
    // Play slightly different sound for enter
    if (audioContextRef.current && soundEnabled) {
      const ctx = audioContextRef.current;
      const osc = ctx.createOscillator();
      const gainNode = ctx.createGain();
      osc.type = "triangle";
      osc.frequency.setValueAtTime(300, ctx.currentTime);
      osc.frequency.exponentialRampToValueAtTime(100, ctx.currentTime + 0.1);
      gainNode.gain.setValueAtTime(0.1, ctx.currentTime);
      gainNode.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.1);
      osc.connect(gainNode);
      gainNode.connect(ctx.destination);
      osc.start();
      osc.stop(ctx.currentTime + 0.1);
    }

    setTimeout(() => {
      onSelectAction();
      onOpenChange(false);
      setInputValue("");
    }, 150);
  };

  return (
    <>
      {/* 
        Tailwind CSS for CRT effects. We inject these here to avoid bloating global CSS.
        Usually better in a stylesheet, but fine for a drop-in component.
      */}
      <style dangerouslySetInnerHTML={{__html: `
        .crt-overlay {
          background: linear-gradient(
            to bottom,
            rgba(255,255,255,0),
            rgba(255,255,255,0) 50%,
            rgba(0,0,0,0.2) 50%,
            rgba(0,0,0,0.2)
          );
          background-size: 100% 4px;
          pointer-events: none;
        }
        @keyframes crt-flicker {
          0% { opacity: 0.95; }
          5% { opacity: 0.85; }
          10% { opacity: 0.95; }
          100% { opacity: 0.98; }
        }
        .animate-crt {
          animation: crt-flicker 0.15s infinite;
        }
        .phosphor-glow {
          text-shadow: 0 0 5px rgba(52, 211, 153, 0.8), 0 0 10px rgba(52, 211, 153, 0.4);
        }

        /* cmdk specific styles to override default headless behavior */
        [cmdk-root] {
          width: 100%;
          background: transparent;
