"use client";

import React, { useRef, useState, useEffect } from "react";
import { motion, useScroll, useMotionValueEvent, useTransform } from "framer-motion";
import { cn } from "@/lib/utils";

export interface TextNode {
  content: React.ReactNode;
  /** Scroll progress value (0 to 1) when the text starts fading in */
  start: number;
  /** Scroll progress value (0 to 1) when the text has fully faded out */
  end: number;
}

export interface ScrollVideoScrubProps {
  videoUrl: string;
  className?: string;
  fallbackImage?: string;
  /** Array of text overlays tied to scroll progress timestamps */
  textNodes?: TextNode[];
}

export function ScrollVideoScrub({ videoUrl, className, fallbackImage, textNodes = [] }: ScrollVideoScrubProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const [isVideoLoaded, setIsVideoLoaded] = useState(false);
  const [duration, setDuration] = useState(0);

  // We track the scroll progress over a massive container (e.g., 300vh)
  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start start", "end end"]
  });

  // When metadata loads, we know exactly how long the video is
  const handleLoadedMetadata = () => {
    if (videoRef.current) {
      setDuration(videoRef.current.duration);
      setIsVideoLoaded(true);
    }
  };

  // Every time the scroll position changes, we update the video's current time
  // to perfectly match the scroll percentage!
  useMotionValueEvent(scrollYProgress, "change", (latest) => {
    if (videoRef.current && isVideoLoaded) {
      // Small math to ensure we don't try to seek past the very end, which sometimes causes a glitch
      const targetTime = latest * duration;
      // Use requestAnimationFrame for smoother performance when rapidly scrolling
      requestAnimationFrame(() => {
        if (videoRef.current) {
          videoRef.current.currentTime = targetTime;
        }
      });
    }
  });

  // Optional: We can add a fade-in text overlay that triggers at certain scroll points
  const titleOpacity = useTransform(scrollYProgress, [0, 0.2, 0.8, 1], [1, 0, 0, 1]);
  const titleScale = useTransform(scrollYProgress, [0, 0.2, 0.8, 1], [1, 0.9, 0.9, 1]);

  return (
    <div 
      ref={containerRef} 
      className={cn("relative h-[400vh] w-full bg-zinc-950", className)}
    >
      <div className="sticky top-0 w-full h-screen overflow-hidden flex items-center justify-center bg-black">

        {/* The scrubbing video */}
        <video
          ref={videoRef}
          src={videoUrl}
          preload="auto"
          muted
          playsInline
          onLoadedMetadata={handleLoadedMetadata}
          className={cn(
            "w-full h-full object-cover transition-opacity duration-1000",
            isVideoLoaded ? "opacity-100" : "opacity-0"
          )}
        />

        {/* Fallback while loading */}
        {!isVideoLoaded && fallbackImage && (
          <img 
            src={fallbackImage} 
            alt="Loading video" 
            className="absolute inset-0 w-full h-full object-cover opacity-50"
          />
        )}

        {/* Dynamic Text Overlays */}
        {textNodes.map((node, i) => (
          <TextNodeOverlay 
            key={i} 
            node={node} 
            scrollYProgress={scrollYProgress} 
          />
        ))}

        {/* Progress indicator at the bottom */}
        <div className="absolute bottom-10 left-10 right-10 h-1 bg-white/20 rounded-full overflow-hidden">
          <motion.div 
            className="h-full bg-white origin-left"
            style={{ scaleX: scrollYProgress }}
          />
        </div>

      </div>
    </div>
  );
}

// Sub-component to safely call useTransform for each dynamic node
function TextNodeOverlay({ 
  node, 
  scrollYProgress 
}: { 
  node: TextNode; 
  scrollYProgress: any;
}) {
  // We want to fade in from start, stay fully visible for a bit, then fade out by end.
  // We'll calculate a small transition window (e.g., 5% of scroll).
  const transitionWindow = 0.05;
  const fadeInEnd = Math.min(node.start + transitionWindow, node.end);
  const fadeOutStart = Math.max(node.end - transitionWindow, node.start);

  const opacity = useTransform(
    scrollYProgress, 
    [node.start, fadeInEnd, fadeOutStart, node.end], 
    [0, 1, 1, 0]
  );

  const y = useTransform(
    scrollYProgress,
    [node.start, fadeInEnd, fadeOutStart, node.end],
    [30, 0, 0, -30]
  );

  return (
    <motion.div 
      className="absolute inset-0 flex items-center justify-center pointer-events-none"
      style={{ opacity, y }}
    >
      <div className="bg-black/60 p-8 md:p-12 backdrop-blur-md rounded-3xl border border-white/10 text-center max-w-3xl">
        {node.content}
      </div>
    </motion.div>
  );
}

"use client";

import React, { useEffect, useRef } from "react";
import Lenis from "lenis";

export interface SmoothScrollProps {
  children: React.ReactNode;
  duration?: number;
  easing?: (t: number) => number;
  smoothTouch?: boolean;
  touchMultiplier?: number;
  containerRef?: React.RefObject<any>;
}

export function SmoothScroll({
  children,
  duration = 1.2,
  easing = (t: number) => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
  smoothTouch = false,
  touchMultiplier = 2,
  containerRef,
}: SmoothScrollProps) {
  const reqIdRef = useRef<number>(0);
  const lenisRef = useRef<Lenis | null>(null);

  useEffect(() => {
    const lenis = new Lenis({
      ...(containerRef?.current ? { wrapper: containerRef.current } : {}),
      duration,
      easing,
      smoothWheel: true,
      syncTouch: smoothTouch,
      touchMultiplier,
    });
    lenisRef.current = lenis;

    const animate = (time: number) => {
      lenis.raf(time);
      reqIdRef.current = requestAnimationFrame(animate);
    };

    reqIdRef.current = requestAnimationFrame(animate);

    return () => {
      cancelAnimationFrame(reqIdRef.current);
      lenis.destroy();
    };
  }, [duration, easing, smoothTouch, touchMultiplier]);

  return <>{children}</>;
}

"use client";

import React, { useRef, useMemo, useState, useEffect } from "react";
import { Canvas, useFrame, useThree } from "@react-three/fiber";
import { Html, Environment } from "@react-three/drei";
import { motion, useScroll, useTransform, MotionValue } from "framer-motion";
import * as THREE from "three";
import { cn } from "@/lib/utils";

interface TunnelScrollProps extends React.HTMLAttributes<HTMLDivElement> {
  children: React.ReactNode;
  /** Spacing in 3D units between each child */
  spacing?: number;
  /** Base color of the neon tunnel */
  tunnelColor?: string;
}

// ─── THE TUNNEL MESH ───
function Tunnel({ length, color }: { length: number; color: string }) {
  const meshRef = useRef<THREE.Mesh>(null);
  const materialRef = useRef<THREE.MeshStandardMaterial>(null);

  useFrame((state, delta) => {
    if (meshRef.current) {
      meshRef.current.rotation.z += delta * 0.1;
    }
    if (materialRef.current) {
      // Pulse the emissive intensity slightly
      materialRef.current.emissiveIntensity = 1 + Math.sin(state.clock.elapsedTime * 2) * 0.3;
    }
  });

  return (
    <mesh ref={meshRef} position={[0, 0, -length / 2]} rotation={[Math.PI / 2, 0, 0]}>
      {/* Cylinder extending along the Z axis (rotated 90deg on X) */}
      <cylinderGeometry args={[8, 8, length + 20, 32, Math.floor(length / 2), true]} />
      <meshStandardMaterial
        ref={materialRef}
        color={color}
        emissive={color}
        emissiveIntensity={1}
        wireframe={true}
        side={THREE.BackSide}
      />
    </mesh>
  );
}

// ─── THE SCENE CAMERA CONTROLLER ───
function SceneController({
  scrollYProgress,
  maxZ,
}: {
  scrollYProgress: MotionValue<number>;
  maxZ: number;
}) {
  const { camera } = useThree();

  useFrame(() => {
    // Read the framer-motion scroll progress (0 to 1)
    const progress = scrollYProgress.get();

    // Target Z position for the camera
    const targetZ = progress * -maxZ;

    // Smoothly interpolate the camera position
    camera.position.z = THREE.MathUtils.lerp(camera.position.z, targetZ, 0.08);

    // Optional: Add a slight shake or sway based on movement
    camera.rotation.z = THREE.MathUtils.lerp(
      camera.rotation.z, 
      Math.sin(progress * Math.PI * 4) * 0.05, 
      0.08
    );
  });

  return null;
}

// ─── THE MAIN WRAPPER ───
export function TunnelScroll({
  children,
  spacing = 30,
  tunnelColor = "#6366f1", // indigo-500
  className,
  ...props
}: TunnelScrollProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  // Convert children to array and filter out nulls/booleans
  const childrenArray = useMemo(
    () => React.Children.toArray(children).filter(Boolean),
    [children]
  );

  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start start", "end end"],
  });

  const maxZ = (childrenArray.length - 1) * spacing;

  // Render a placeholder during SSR to avoid hydration mismatches with Canvas
  const [mounted, setMounted] = useState(false);
  useEffect(() => setMounted(true), []);

  return (
    <div
      ref={containerRef}
      className={cn("relative w-full", className)}
      // Create a tall scrolling container. e.g., 200vh per child section.
      style={{ height: `${childrenArray.length * 150}vh` }}
      {...props}
    >
      <div className="sticky top-0 left-0 w-full h-screen overflow-hidden bg-black">
        {mounted && (
          <Canvas
            camera={{ position: [0, 0, 5], fov: 75 }}
            gl={{ antialias: true, alpha: false }}
          >
            {/* Environment and Lighting */}
            <color attach="background" args={["#000000"]} />
            <fog attach="fog" args={["#000000", 0, spacing * 1.5]} />
            <ambientLight intensity={0.5} />
            <Environment preset="city" />

            {/* The Infinite Tunnel */}
            <Tunnel length={maxZ} color={tunnelColor} />

            {/* Render Children as 3D Billboards */}
            {childrenArray.map((child, i) => {
              const zPosition = -i * spacing;
              return (
                <group key={i} position={[0, 0, zPosition]}>
                  {/* We use scale to ensure the HTML element looks sharp but is sized reasonably in 3D space */}
                  <Html
                    transform
                    center
                    distanceFactor={15} // Keeps elements looking consistent at distance
                    className="flex items-center justify-center pointer-events-auto"
                    style={{
                      // It's highly recommended to use fixed widths on the actual children passed to this component
                      // so they don't try to infinitely expand inside the 3D projection.
                      width: "100%",
                      maxWidth: "1000px", 
                    }}
                  >
                    <div className="w-full flex items-center justify-center opacity-100">
                      {child}
                    </div>
                  </Html>
                </group>
              );
            })}

            {/* Handles moving the camera forward based on scroll */}
            <SceneController scrollYProgress={scrollYProgress} maxZ={maxZ} />
          </Canvas>
        )}
      </div>
    </div>
  );
}

"use client";

import React, { useRef } from "react";
import { motion, useScroll, useTransform } from "framer-motion";
import { cn } from "@/lib/utils";

export interface ScrollLinkedSplitProps extends React.HTMLAttributes<HTMLDivElement> {
  leftContent: React.ReactNode;
  rightContent: React.ReactNode;
  revealContent: React.ReactNode;
  splitRatio?: "50/50" | "40/60" | "60/40";
  direction?: "horizontal" | "vertical";
  offset?: number;
  scrollContainerRef?: React.RefObject<any>;
  stickyHeight?: string;
}

const ratioClasses = {
  "50/50": "grid-cols-2",
  "40/60": "grid-cols-[4fr_6fr]",
  "60/40": "grid-cols-[6fr_4fr]",
};

export function ScrollLinkedSplit({
  leftContent,
  rightContent,
  revealContent,
  splitRatio = "50/50",
  direction = "horizontal",
  offset = 100, // percentage to move out
  scrollContainerRef,
  stickyHeight = "100vh",
  className,
  ...props
}: ScrollLinkedSplitProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  const { scrollYProgress } = useScroll({
    target: containerRef,
    ...(scrollContainerRef ? { container: scrollContainerRef } : {}),
    offset: ["start start", "end end"]
  });

  // Calculate transforms based on direction
  const leftX = useTransform(scrollYProgress, [0, 1], ["0%", `-${offset}%`]);
  const rightX = useTransform(scrollYProgress, [0, 1], ["0%", `${offset}%`]);

  const topY = useTransform(scrollYProgress, [0, 1], ["0%", `-${offset}%`]);
  const bottomY = useTransform(scrollYProgress, [0, 1], ["0%", `${offset}%`]);

  return (
    <div
      ref={containerRef}
      className={cn("relative w-full h-[150vh]", className)}
      {...props}
    >
      <div 
        className="sticky top-0 w-full overflow-hidden flex items-center justify-center"
        style={{ height: stickyHeight }}
      >
        {/* The content revealed underneath */}
        <div className="absolute inset-0 z-0 flex items-center justify-center">
          {revealContent}
        </div>

        {/* The splitting panels */}
        {direction === "horizontal" ? (
          <div className={cn("absolute inset-0 z-10 grid w-full h-full", ratioClasses[splitRatio])}>
            <motion.div 
              className="h-full w-full bg-background border-r border-border shadow-xl origin-left"
              style={{ x: leftX }}
            >
              {leftContent}
            </motion.div>
            <motion.div 
              className="h-full w-full bg-background border-l border-border shadow-xl origin-right"
              style={{ x: rightX }}
            >
              {rightContent}
            </motion.div>
          </div>
        ) : (
          <div className="absolute inset-0 z-10 flex flex-col w-full h-full">
            <motion.div 
              className="h-1/2 w-full bg-background border-b border-border shadow-xl origin-top"
              style={{ y: topY }}
            >
              {leftContent}
            </motion.div>
            <motion.div 
              className="h-1/2 w-full bg-background border-t border-border shadow-xl origin-bottom"
              style={{ y: bottomY }}
            >
              {rightContent}
            </motion.div>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import React, { useRef, useState } from "react";
import { motion } from "framer-motion";
import { cn } from "@/lib/utils";

export type MagneticVariant = "standard" | "heavy" | "bouncy";

interface MagneticButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  children: React.ReactNode;
  className?: string;
  magneticPull?: number;
  scale?: number;
  speed?: number;
  color?: string;
  withSound?: boolean;
  variant?: MagneticVariant;
}

export function MagneticButton({
  children,
  className,
  magneticPull = 0.3,
  scale,
  speed,
  color,
  withSound = false,
  variant = "standard",
  ...props
}: MagneticButtonProps) {
  const buttonRef = useRef<HTMLButtonElement>(null);
  const [position, setPosition] = useState({ x: 0, y: 0 });

  const handleMouseMove = (e: React.MouseEvent<HTMLButtonElement>) => {
    const { clientX, clientY } = e;
    const { height, width, left, top } = buttonRef.current!.getBoundingClientRect();

    const middleX = clientX - (left + width / 2);
    const middleY = clientY - (top + height / 2);

    const activePull = scale !== undefined ? scale * 0.35 : magneticPull;

    setPosition({
      x: middleX * activePull,
      y: middleY * activePull,
    });
  };

  const handleMouseLeave = (e: React.MouseEvent<HTMLButtonElement>) => {
    setPosition({ x: 0, y: 0 });
    if (props.onMouseLeave) props.onMouseLeave(e);
  };

  const handleMouseEnter = (e: React.MouseEvent<HTMLButtonElement>) => {
    if (props.onMouseEnter) props.onMouseEnter(e);
  };

  const handleClick = (e: React.MouseEvent<HTMLButtonElement>) => {
    if (props.onClick) props.onClick(e);
  };

  const hasBg = className?.includes("bg-");
  const hasText = className?.includes("text-");
  const isTransparent = className?.includes("bg-transparent") || className?.includes("border");

  const customStyle: React.CSSProperties = { ...props.style };
  if (color) {
    if (isTransparent) {
      if (!customStyle.borderColor) customStyle.borderColor = color;
      if (!customStyle.color) customStyle.color = color;
    } else {
      if (!customStyle.backgroundColor) customStyle.backgroundColor = color;
      if (!customStyle.color) customStyle.color = "#ffffff";
    }
  }

  const getPhysics = () => {
    const baseSpeed = speed || 1;
    switch (variant) {
      case "heavy":
        return { stiffness: 100 * baseSpeed, damping: 30 / baseSpeed, mass: 2 };
      case "bouncy":
        return { stiffness: 400 * baseSpeed, damping: 10 / baseSpeed, mass: 0.5 };
      case "standard":
      default:
        return { stiffness: 150 * baseSpeed, damping: 15 / baseSpeed, mass: 0.1 };
    }
  };

  const physics = getPhysics();

  return (
    <motion.button
      ref={buttonRef}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      onMouseEnter={handleMouseEnter}
      onClick={handleClick}
      animate={{ x: position.x, y: position.y }}
      transition={{ type: "spring", ...physics }}
      className={cn(
        "relative inline-flex items-center justify-center rounded-full px-6 py-3 text-sm font-semibold transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50",
        !hasBg && "bg-primary hover:bg-primary/90",
        !hasText && "text-primary-foreground",
        className
      )}
      style={customStyle}
      {...(props as any)}
    >
      <motion.span
        className="inline-flex items-center justify-center"
        animate={{ x: position.x * 0.2, y: position.y * 0.2 }}
        transition={{ type: "spring", ...physics }}
      >
        {children}
      </motion.span>
    </motion.button>
  );
}

"use client";

import React, { useRef, useMemo, useEffect } from "react";
import { Canvas, useFrame, useThree } from "@react-three/fiber";
import * as THREE from "three";
import { cn } from "@/lib/utils";

const vertexShader = `
varying vec2 vUv;
void main() {
  vUv = uv;
  gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
}
`;

const fragmentShader = `
uniform float uTime;
uniform vec2 uResolution;
uniform vec2 uMouse;
uniform vec3 uColor1;
uniform vec3 uColor2;
uniform vec3 uColor3;

varying vec2 vUv;

// Simplex 2D noise
vec3 permute(vec3 x) { return mod(((x*34.0)+1.0)*x, 289.0); }
float snoise(vec2 v){
  const vec4 C = vec4(0.211324865405187, 0.366025403784439,
           -0.577350269189626, 0.024390243902439);
  vec2 i  = floor(v + dot(v, C.yy) );
  vec2 x0 = v -   i + dot(i, C.xx);
  vec2 i1;
  i1 = (x0.x > x0.y) ? vec2(1.0, 0.0) : vec2(0.0, 1.0);
  vec4 x12 = x0.xyxy + C.xxzz;
  x12.xy -= i1;
  i = mod(i, 289.0);
  vec3 p = permute( permute( i.y + vec3(0.0, i1.y, 1.0 ))
  + i.x + vec3(0.0, i1.x, 1.0 ));
  vec3 m = max(0.5 - vec3(dot(x0,x0), dot(x12.xy,x12.xy), dot(x12.zw,x12.zw)), 0.0);
  m = m*m ;
  m = m*m ;
  vec3 x = 2.0 * fract(p * C.www) - 1.0;
  vec3 h = abs(x) - 0.5;
  vec3 ox = floor(x + 0.5);
  vec3 a0 = x - ox;
  m *= 1.79284291400159 - 0.85373472095314 * ( a0*a0 + h*h );
  vec3 g;
  g.x  = a0.x  * x0.x  + h.x  * x0.y;
  g.yz = a0.yz * x12.xz + h.yz * x12.yw;
  return 130.0 * dot(m, g);
}

void main() {
  vec2 uv = vUv;

  // Base distortion
  float noise1 = snoise(uv * 2.0 + uTime * 0.05);
  float noise2 = snoise(uv * 3.0 - uTime * 0.08 + noise1);

  // Mouse influence
  float mouseDist = distance(uv, uMouse);
  float mouseInfluence = smoothstep(0.6, 0.0, mouseDist);
  vec2 distortedUv = uv + noise2 * 0.15 + mouseInfluence * 0.2 * vec2(snoise(uv + uTime), snoise(uv - uTime));

  // Layered noise for color mixing
  float n1 = snoise(distortedUv * 2.0 + uTime * 0.1);
  float n2 = snoise(distortedUv * 4.0 - uTime * 0.15);

  // Mix colors
  vec3 colorA = mix(uColor1, uColor2, n1 * 0.5 + 0.5);
  vec3 finalColor = mix(colorA, uColor3, n2 * 0.5 + 0.5);

  // Subtle vignette
  float vignette = 1.0 - smoothstep(0.4, 1.5, length(uv - 0.5));

  gl_FragColor = vec4(finalColor * vignette, 1.0);
}
`;

function Scene({
  color1,
  color2,
  color3,
  speed = 1,
}: {
  color1: string;
  color2: string;
  color3: string;
  speed?: number;
}) {
  const { viewport, size } = useThree();
  const materialRef = useRef<THREE.ShaderMaterial>(null);

  // Track mouse coordinates globally
  const mouse = useRef(new THREE.Vector2(0.5, 0.5));

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      mouse.current.x = e.clientX / window.innerWidth;
      mouse.current.y = 1.0 - (e.clientY / window.innerHeight); // GLSL coords are bottom-left
    };
    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, []);

  const uniforms = useMemo(
    () => ({
      uTime: { value: 0 },
      uResolution: { value: new THREE.Vector2(size.width, size.height) },
      uMouse: { value: new THREE.Vector2(0.5, 0.5) },
      uColor1: { value: new THREE.Color(color1) },
      uColor2: { value: new THREE.Color(color2) },
      uColor3: { value: new THREE.Color(color3) },
    }),
    [color1, color2, color3, size]
  );

  useFrame((state, delta) => {
    if (materialRef.current) {
      materialRef.current.uniforms.uTime.value += delta * speed;
      materialRef.current.uniforms.uResolution.value.set(size.width, size.height);
      // Smoothly interpolate mouse to avoid jerky movement
      materialRef.current.uniforms.uMouse.value.lerp(mouse.current, 0.05);
    }
  });

  return (
    <mesh>
      <planeGeometry args={[viewport.width, viewport.height]} />
      <shaderMaterial
        ref={materialRef}
        vertexShader={vertexShader}
        fragmentShader={fragmentShader}
        uniforms={uniforms}
      />
    </mesh>
  );
}

interface FluidBackgroundProps {
  color1?: string;
  color2?: string;
  color3?: string;
  speed?: number;
  className?: string;
}

export function FluidBackground({
