// ─── Ring Variant: Torus knot with metallic finish ────────────────────────────
function RingScene({ color = '#f59e0b', speed = 1, scale = 1 }: { color?: string; speed?: number; scale?: number }) {
  const meshRef = useRef<THREE.Mesh>(null);

  useFrame((state) => {
