"use client";

import React, { useRef, useState, useMemo, Suspense } from "react";
import { Canvas, useFrame, useThree } from "@react-three/fiber";
import { useTexture } from "@react-three/drei";
import * as THREE from "three";
import { cn } from "@/lib/utils";

const vertexShader = `
varying vec2 vUv;
void main() {
  vUv = uv;
  gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
}
`;

const fragmentShader = `
uniform sampler2D tex1;
uniform sampler2D tex2;
uniform float progress;
uniform float pixels;
uniform vec2 resolution;
varying vec2 vUv;

float rand(vec2 co) {
  return fract(sin(dot(co.xy ,vec2(12.9898,78.233))) * 43758.5453);
}

void main() {
  // Use resolution to make pixels square
  vec2 aspect = vec2(resolution.x / resolution.y, 1.0);
  vec2 uv = vUv;

  // Grid based on aspect ratio
  vec2 gridId = floor(uv * aspect * pixels);
  float r = rand(gridId);

  // Add some distortion based on progress
  vec2 distortedUv = uv;
  if(progress > 0.0 && progress < 1.0) {
     float wave = sin(progress * 3.1415);
     distortedUv += (r - 0.5) * 0.05 * wave;
  }

  // Smoothstep for the pixel transition
  float mixProgress = smoothstep(r - 0.2, r + 0.2, progress);

  vec4 color1 = texture2D(tex1, distortedUv);
  vec4 color2 = texture2D(tex2, distortedUv);

  gl_FragColor = mix(color1, color2, mixProgress);
}
`;

function Scene({
  src1,
  src2,
  isHovered,
  gridSize,
}: {
  src1: string;
  src2: string;
  isHovered: boolean;
  gridSize: number;
}) {
  const { viewport, size } = useThree();
  const [texture1, texture2] = useTexture([src1, src2]);

  useMemo(() => {
    texture1.colorSpace = THREE.SRGBColorSpace;
    texture2.colorSpace = THREE.SRGBColorSpace;
    texture1.minFilter = THREE.LinearFilter;
    texture2.minFilter = THREE.LinearFilter;
  }, [texture1, texture2]);

  const materialRef = useRef<THREE.ShaderMaterial>(null);

  useFrame((state, delta) => {
    if (materialRef.current) {
      const mat = materialRef.current;
      const target = isHovered ? 1 : 0;
      mat.uniforms.progress.value = THREE.MathUtils.lerp(
        mat.uniforms.progress.value,
        target,
        delta * 3
      );
      mat.uniforms.pixels.value = gridSize;
      mat.uniforms.resolution.value.set(size.width, size.height);
    }
  });

  return (
    <mesh>
      <planeGeometry args={[viewport.width, viewport.height]} />
      <shaderMaterial
        ref={materialRef}
        uniforms={{
          tex1: { value: texture1 },
          tex2: { value: texture2 },
          progress: { value: 0 },
          pixels: { value: gridSize },
          resolution: { value: new THREE.Vector2(size.width, size.height) },
        }}
        vertexShader={vertexShader}
        fragmentShader={fragmentShader}
      />
    </mesh>
  );
}

interface PixelTransitionProps extends React.HTMLAttributes<HTMLDivElement> {
  firstImage: string;
  secondImage: string;
  gridSize?: number;
}

export function PixelTransition({
  firstImage,
  secondImage,
  gridSize = 40,
  className,
  ...props
}: PixelTransitionProps) {
  const [isHovered, setIsHovered] = useState(false);

  return (
    <div
      className={cn("relative overflow-hidden cursor-pointer", className)}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      {...props}
    >
      <Suspense
        fallback={
          <div className="absolute inset-0 bg-zinc-900 animate-pulse flex items-center justify-center">
            <span className="text-zinc-500 text-sm">Loading textures...</span>
          </div>
        }
      >
        <Canvas>
          <Scene
            src1={firstImage}
            src2={secondImage}
            isHovered={isHovered}
            gridSize={gridSize}
          />
        </Canvas>
      </Suspense>
    </div>
  );
}

"use client";

import React, { useRef, useState, useMemo, Suspense } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import { useTexture, shaderMaterial } from "@react-three/drei";
import * as THREE from "three";
import { cn } from "@/lib/utils";

// --- Liquid Ripple Shader ---
const LiquidRippleMaterial = shaderMaterial(
  {
    uTex1: new THREE.Texture(),
    uTex2: new THREE.Texture(),
    uProgress: 0,
    uIntensity: 0.5,
  },
  // Vertex Shader
  `
  varying vec2 vUv;
  void main() {
    vUv = uv;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
  }
  `,
  // Fragment Shader
  `
  varying vec2 vUv;
  uniform sampler2D uTex1;
  uniform sampler2D uTex2;
  uniform float uProgress;
  uniform float uIntensity;

  void main() {
    vec2 uv = vUv;

    // Ripple calculation
    vec2 center = vec2(0.5, 0.5);
    float dist = distance(uv, center);

    // Distort UVs based on distance and progress
    vec2 distortedUv1 = uv + (uv - center) * sin(dist * 20.0 - uProgress * 10.0) * uProgress * uIntensity;
    vec2 distortedUv2 = uv + (uv - center) * sin(dist * 20.0 - uProgress * 10.0) * (1.0 - uProgress) * uIntensity;

    // Sample both textures
    vec4 tex1 = texture2D(uTex1, distortedUv1);
    vec4 tex2 = texture2D(uTex2, distortedUv2);

    // Mix based on progress
    gl_FragColor = mix(tex1, tex2, uProgress);
  }
  `
);

// --- Noise Dissolve Shader ---
const NoiseDissolveMaterial = shaderMaterial(
  {
    uTex1: new THREE.Texture(),
    uTex2: new THREE.Texture(),
    uProgress: 0,
    uIntensity: 1.0,
  },
  // Vertex Shader
  `
  varying vec2 vUv;
  void main() {
    vUv = uv;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
  }
  `,
  // Fragment Shader
  `
  varying vec2 vUv;
  uniform sampler2D uTex1;
  uniform sampler2D uTex2;
  uniform float uProgress;
  uniform float uIntensity;

  // Simple pseudo-random 2D noise function
  float rand(vec2 n) { 
    return fract(sin(dot(n, vec2(12.9898, 4.1414))) * 43758.5453);
  }

  float noise(vec2 p){
    vec2 ip = floor(p);
    vec2 u = fract(p);
    u = u*u*(3.0-2.0*u);

    float res = mix(
      mix(rand(ip), rand(ip+vec2(1.0,0.0)), u.x),
      mix(rand(ip+vec2(0.0,1.0)), rand(ip+vec2(1.0,1.0)), u.x), u.y);
    return res*res;
  }

  void main() {
    vec2 uv = vUv;

    // Generate noise value
    float n = noise(uv * 20.0 * uIntensity);

    // Smoothstep threshold based on progress
    float threshold = smoothstep(uProgress - 0.2, uProgress + 0.2, n);

    // Reverse logic: at progress 0, we want tex1. So when progress is low, threshold is high.
    // Actually, simple step:
    float mixFactor = smoothstep(1.0 - uProgress, 1.0 - uProgress + 0.1, n);

    vec4 tex1 = texture2D(uTex1, uv);
    vec4 tex2 = texture2D(uTex2, uv);

    gl_FragColor = mix(tex1, tex2, uProgress);

    // Apply dissolve organically
    // If progress is higher than noise, show tex2, else tex1
    float stepMask = step(n, uProgress * 1.2); 
    gl_FragColor = mix(tex1, tex2, stepMask);
  }
  `
);

// Register materials with R3F
import { extend } from '@react-three/fiber';
extend({ LiquidRippleMaterial, NoiseDissolveMaterial });

// Add types for JSX
declare global {
  namespace JSX {
    interface IntrinsicElements {
      liquidRippleMaterial: any;
      noiseDissolveMaterial: any;
    }
  }
}

interface ShaderPlaneProps {
  image1: string;
  image2: string;
  effect: "liquid" | "noise";
  isHovered: boolean;
  intensity?: number;
}

function ShaderPlane({ image1, image2, effect, isHovered, intensity = 0.5 }: ShaderPlaneProps) {
  const meshRef = useRef<THREE.Mesh>(null);
  const materialRef = useRef<any>(null);

  // Load textures
  const [tex1, tex2] = useTexture([image1, image2]);

  useFrame((state, delta) => {
    if (materialRef.current) {
      // Lerp progress to target (1 if hovered, 0 if not)
      const target = isHovered ? 1 : 0;
      // Damped lerp for smooth animation
      materialRef.current.uProgress = THREE.MathUtils.lerp(
        materialRef.current.uProgress,
        target,
        delta * 6.0
      );
    }
  });

  return (
    <mesh ref={meshRef}>
      <planeGeometry args={[2, 2]} />
      {effect === "liquid" ? (
        // @ts-ignore
        <liquidRippleMaterial 
          ref={materialRef} 
          uTex1={tex1} 
          uTex2={tex2} 
          uIntensity={intensity}
          transparent={true}
        />
      ) : (
        // @ts-ignore
        <noiseDissolveMaterial 
          ref={materialRef} 
          uTex1={tex1} 
          uTex2={tex2} 
          uIntensity={intensity}
          transparent={true}
        />
      )}
    </mesh>
  );
}

