"use client";

import React, { useState, useEffect, useRef, useMemo } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import { MeshDistortMaterial, Environment } from "@react-three/drei";
import { Play, Pause } from "lucide-react";
import * as THREE from "three";
import { cn } from "@/lib/utils";

interface AudioVisualizer3DProps extends React.HTMLAttributes<HTMLDivElement> {
  audioSrc: string;
  wireframe?: boolean;
  color?: string;
  className?: string;
}

// Separate component for the 3D mesh that hooks into the render loop
function VisualizerMesh({
  analyser,
  dataArray,
  isPlaying,
  wireframe,
  color,
}: {
  analyser: AnalyserNode | null;
  dataArray: Uint8Array | null;
  isPlaying: boolean;
  wireframe: boolean;
  color: string;
}) {
  const meshRef = useRef<THREE.Mesh>(null);
  const materialRef = useRef<any>(null);

  // Smooth out the values using linear interpolation
  const targetScale = useRef(1);
  const targetDistort = useRef(0);

  useFrame((state, delta) => {
    if (!meshRef.current || !materialRef.current) return;

    if (analyser && dataArray && isPlaying) {
      analyser.getByteFrequencyData(dataArray as any);

      // Bass frequencies (lower indices) for scale
      let bassSum = 0;
      for (let i = 0; i < 10; i++) {
        bassSum += dataArray[i];
      }
      const bassAvg = bassSum / 10; // 0 to 255

      // Mids/Highs for distortion
      let highSum = 0;
      for (let i = 20; i < 60; i++) {
        highSum += dataArray[i];
      }
      const highAvg = highSum / 40; // 0 to 255

      // Map values to mesh parameters
      // Scale bounces between 1 and 1.5 based on bass
      targetScale.current = 1 + (bassAvg / 255) * 0.5;

      // Distortion goes from 0.1 to 1.5 based on highs
      targetDistort.current = 0.2 + (highAvg / 255) * 1.5;
    } else {
      // Decay back to rest state when paused/stopped
      targetScale.current = THREE.MathUtils.lerp(targetScale.current, 1, 0.05);
      targetDistort.current = THREE.MathUtils.lerp(targetDistort.current, 0.2, 0.05);
    }

    // Smoothly apply the target values
    meshRef.current.scale.lerp(
      new THREE.Vector3(targetScale.current, targetScale.current, targetScale.current),
      0.15
    );
    materialRef.current.distort = THREE.MathUtils.lerp(
      materialRef.current.distort,
      targetDistort.current,
      0.15
    );

    // Slowly rotate the mesh for a continuous ambient feel
    meshRef.current.rotation.x += delta * 0.2;
    meshRef.current.rotation.y += delta * 0.3;
  });

  return (
    <mesh ref={meshRef}>
      <icosahedronGeometry args={[2, 64]} />
      <MeshDistortMaterial
        ref={materialRef}
        color={color}
        wireframe={wireframe}
        roughness={0.2}
        metalness={0.8}
        speed={2}
      />
    </mesh>
  );
}

export function AudioVisualizer3D({
  audioSrc,
  wireframe = false,
  color = "#6366f1", // indigo-500
  className,
  ...props
}: AudioVisualizer3DProps) {
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const dataArrayRef = useRef<Uint8Array | null>(null);

  // Initialize Audio Context on user interaction (required by browsers)
  const initAudio = () => {
    if (!audioContextRef.current) {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      audioContextRef.current = ctx;

      if (audioRef.current) {
        const source = ctx.createMediaElementSource(audioRef.current);
        const analyser = ctx.createAnalyser();
        // High FFT size for smooth data
        analyser.fftSize = 512;
        // Smoothing time constant prevents jitter
        analyser.smoothingTimeConstant = 0.8;

        source.connect(analyser);
        analyser.connect(ctx.destination);

        analyserRef.current = analyser;
        dataArrayRef.current = new Uint8Array(analyser.frequencyBinCount);
      }
    }
  };

  const togglePlay = () => {
    initAudio();
    if (audioRef.current) {
      if (isPlaying) {
        audioRef.current.pause();
      } else {
        audioContextRef.current?.resume();
        audioRef.current.play();
      }
      setIsPlaying(!isPlaying);
    }
  };

  // Handle track ending
  useEffect(() => {
    const audio = audioRef.current;
    if (audio) {
      const onEnded = () => setIsPlaying(false);
      audio.addEventListener("ended", onEnded);
      return () => audio.removeEventListener("ended", onEnded);
    }
  }, []);

  return (
    <div className={cn("relative w-full h-[500px] overflow-hidden rounded-2xl bg-zinc-950", className)} {...props}>
      <audio ref={audioRef} src={audioSrc} crossOrigin="anonymous" preload="auto" />

      {/* 3D Canvas */}
      <div className="absolute inset-0">
        <Canvas camera={{ position: [0, 0, 5], fov: 60 }}>
          <ambientLight intensity={0.5} />
          <directionalLight position={[10, 10, 5]} intensity={1} />
          <Environment preset="city" />

          <VisualizerMesh 
            analyser={analyserRef.current}
            dataArray={dataArrayRef.current}
            isPlaying={isPlaying}
            wireframe={wireframe}
            color={color}
          />
        </Canvas>
      </div>

      {/* Control Overlay */}
      <div className="absolute bottom-6 left-1/2 transform -translate-x-1/2 flex items-center justify-center pointer-events-none">
        <button
          onClick={togglePlay}
          className="pointer-events-auto relative z-10 flex h-14 w-14 items-center justify-center rounded-full bg-white/10 backdrop-blur-md text-white border border-white/20 shadow-2xl transition-all hover:scale-110 hover:bg-white/20 active:scale-95 outline-none"
          aria-label={isPlaying ? "Pause" : "Play"}
        >
          {isPlaying ? (
            <Pause className="h-5 w-5 fill-current" />
          ) : (
            <Play className="h-5 w-5 fill-current ml-1" />
          )}
        </button>
      </div>
    </div>
  );
}

"use client";

import React, { useRef, useState, useCallback, useEffect, useMemo } from "react";
import { Canvas, useFrame, useThree } from "@react-three/fiber";
import * as THREE from "three";
import { cn } from "@/lib/utils";

// ─────────────────────────────────────────────
// GLSL Fragment Shader: Distorted Transition
// ─────────────────────────────────────────────
const vertexShader = /* glsl */ `
  varying vec2 vUv;
  void main() {
    vUv = uv;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
  }
`;

const fragmentShader = /* glsl */ `
  uniform sampler2D uTextureCurrent;
  uniform sampler2D uTextureNext;
  uniform float uProgress;
  uniform float uIntensity;
  uniform vec2 uResolution;

  varying vec2 vUv;

  // Simple 2D noise for distortion
  float random(vec2 st) {
    return fract(sin(dot(st.xy, vec2(12.9898, 78.233))) * 43758.5453123);
  }

  float noise(vec2 st) {
    vec2 i = floor(st);
    vec2 f = fract(st);
    float a = random(i);
    float b = random(i + vec2(1.0, 0.0));
    float c = random(i + vec2(0.0, 1.0));
    float d = random(i + vec2(1.0, 1.0));
    vec2 u = f * f * (3.0 - 2.0 * f);
    return mix(a, b, u.x) + (c - a) * u.y * (1.0 - u.x) + (d - b) * u.x * u.y;
  }

  void main() {
    vec2 uv = vUv;
    float p = uProgress;

    // ─── Chromatic Aberration (RGB Split) ───
    // As progress increases, each color channel samples from a slightly offset UV.
    float aberrationStrength = uIntensity * p * (1.0 - p) * 4.0; // Peaks at p=0.5
    vec2 redOffset   = vec2(aberrationStrength * 0.02, 0.0);
    vec2 greenOffset = vec2(0.0, 0.0);
    vec2 blueOffset  = vec2(-aberrationStrength * 0.02, aberrationStrength * 0.01);

    // ─── Liquid Noise Distortion ───
    float noiseVal = noise(uv * 8.0 + p * 3.0);
    vec2 distortion = vec2(
      noiseVal * aberrationStrength * 0.05,
      noiseVal * aberrationStrength * 0.03
    );

    // ─── Wave Displacement ───
    float wave = sin(uv.y * 20.0 + p * 12.0) * aberrationStrength * 0.01;
    vec2 waveOffset = vec2(wave, 0.0);

    // Final distorted UVs for both textures
    vec2 uvDistorted = uv + distortion + waveOffset;

    // Sample current image (with RGB split)
    float currentR = texture2D(uTextureCurrent, uvDistorted + redOffset).r;
    float currentG = texture2D(uTextureCurrent, uvDistorted + greenOffset).g;
    float currentB = texture2D(uTextureCurrent, uvDistorted + blueOffset).b;
    vec4 colorCurrent = vec4(currentR, currentG, currentB, 1.0);

    // Sample next image (with RGB split)
    float nextR = texture2D(uTextureNext, uvDistorted + redOffset).r;
    float nextG = texture2D(uTextureNext, uvDistorted + greenOffset).g;
    float nextB = texture2D(uTextureNext, uvDistorted + blueOffset).b;
    vec4 colorNext = vec4(nextR, nextG, nextB, 1.0);

    // ─── Dissolve Mask ───
    // Use noise to create a non-linear transition boundary
    float dissolve = noise(uv * 5.0 + vec2(p * 2.0, 0.0));
    float mixFactor = smoothstep(p - 0.3, p + 0.3, dissolve);

    // Final mix: dissolve from current to next
    vec4 finalColor = mix(colorNext, colorCurrent, mixFactor);

    gl_FragColor = finalColor;
  }
`;

// ─────────────────────────────────────────────
// Internal Scene Component
// ─────────────────────────────────────────────
interface TransitionPlaneProps {
  images: string[];
  currentIndex: number;
  nextIndex: number;
  progress: React.MutableRefObject<number>;
  isTransitioning: boolean;
  intensity: number;
}

function TransitionPlane({ images, currentIndex, nextIndex, progress, isTransitioning, intensity }: TransitionPlaneProps) {
  const meshRef = useRef<THREE.Mesh>(null);
  const materialRef = useRef<THREE.ShaderMaterial>(null);
  const { viewport } = useThree();

  // Load all textures
  const textures = useMemo(() => {
    const loader = new THREE.TextureLoader();
    return images.map((src) => {
      const tex = loader.load(src);
      tex.minFilter = THREE.LinearFilter;
      tex.magFilter = THREE.LinearFilter;
      return tex;
    });
  }, [images]);

  // Animate progress
  useFrame((_, delta) => {
    if (!materialRef.current) return;

    if (isTransitioning) {
      progress.current = Math.min(progress.current + delta * 1.2, 1.0);
    }

    materialRef.current.uniforms.uProgress.value = progress.current;
    materialRef.current.uniforms.uTextureCurrent.value = textures[currentIndex] || textures[0];
    materialRef.current.uniforms.uTextureNext.value = textures[nextIndex] || textures[0];
  });

  const uniforms = useMemo(() => ({
    uTextureCurrent: { value: textures[0] },
    uTextureNext: { value: textures[0] },
    uProgress: { value: 0 },
    uIntensity: { value: intensity },
    uResolution: { value: new THREE.Vector2(viewport.width, viewport.height) },
  }), [textures, intensity, viewport.width, viewport.height]);

  return (
    <mesh ref={meshRef} scale={[viewport.width, viewport.height, 1]}>
      <planeGeometry args={[1, 1, 32, 32]} />
      <shaderMaterial
        ref={materialRef}
        vertexShader={vertexShader}
        fragmentShader={fragmentShader}
        uniforms={uniforms}
      />
    </mesh>
  );
}

// ─────────────────────────────────────────────
// Public Component
// ─────────────────────────────────────────────
export interface WebGLGalleryProps extends React.HTMLAttributes<HTMLDivElement> {
  /** Array of image URLs */
  images: string[];
  /** Distortion intensity (default 1.0) */
  intensity?: number;
  /** Show navigation controls */
  showControls?: boolean;
  /** Show image counter */
  showCounter?: boolean;
  /** Aspect ratio (default "16/9") */
  aspectRatio?: string;
}

export function WebGLGallery({
  images,
  intensity = 1.0,
  showControls = true,
  showCounter = true,
  aspectRatio = "16/9",
  className,
  ...props
}: WebGLGalleryProps) {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [nextIndex, setNextIndex] = useState(0);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const progressRef = useRef(0);

  const goTo = useCallback((targetIndex: number) => {
    if (isTransitioning || targetIndex === currentIndex) return;

    setNextIndex(targetIndex);
    setIsTransitioning(true);
    progressRef.current = 0;

    // Wait for the transition to finish
    setTimeout(() => {
      setCurrentIndex(targetIndex);
      setIsTransitioning(false);
      progressRef.current = 0;
    }, 900); // ~1 second transition
  }, [isTransitioning, currentIndex]);

  const goNext = useCallback(() => {
    const next = (currentIndex + 1) % images.length;
    goTo(next);
  }, [currentIndex, images.length, goTo]);

  const goPrev = useCallback(() => {
    const prev = (currentIndex - 1 + images.length) % images.length;
    goTo(prev);
  }, [currentIndex, images.length, goTo]);

  return (
    <div
      className={cn("relative w-full overflow-hidden rounded-2xl bg-black group", className)}
      style={{ aspectRatio }}
      {...props}
    >
      {/* WebGL Canvas */}
      <Canvas
        camera={{ position: [0, 0, 5], fov: 45 }}
        gl={{ antialias: true, alpha: false }}
        style={{ position: "absolute", inset: 0 }}
      >
        <TransitionPlane
          images={images}
          currentIndex={currentIndex}
          nextIndex={nextIndex}
          progress={progressRef}
          isTransitioning={isTransitioning}
          intensity={intensity}
        />
      </Canvas>

      {/* Navigation Controls */}
      {showControls && (
        <>
          <button
            onClick={goPrev}
            disabled={isTransitioning}
            className="absolute left-4 top-1/2 -translate-y-1/2 z-10 w-12 h-12 rounded-full bg-white/10 backdrop-blur-md border border-white/20 flex items-center justify-center text-white opacity-0 group-hover:opacity-100 transition-all duration-300 hover:bg-white/20 hover:scale-110 disabled:opacity-30 disabled:cursor-not-allowed"
            aria-label="Previous"
          >
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M15 18l-6-6 6-6"/></svg>
          </button>
          <button
            onClick={goNext}
            disabled={isTransitioning}
            className="absolute right-4 top-1/2 -translate-y-1/2 z-10 w-12 h-12 rounded-full bg-white/10 backdrop-blur-md border border-white/20 flex items-center justify-center text-white opacity-0 group-hover:opacity-100 transition-all duration-300 hover:bg-white/20 hover:scale-110 disabled:opacity-30 disabled:cursor-not-allowed"
            aria-label="Next"
          >
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M9 18l6-6-6-6"/></svg>
          </button>
        </>
      )}

      {/* Image Counter */}
      {showCounter && (
        <div className="absolute bottom-4 left-1/2 -translate-x-1/2 z-10 flex items-center gap-2">
          {images.map((_, i) => (
            <button
              key={i}
              onClick={() => goTo(i)}
              disabled={isTransitioning}
              className={cn(
                "w-2 h-2 rounded-full transition-all duration-300",
                i === currentIndex
                  ? "bg-white w-6"
                  : "bg-white/40 hover:bg-white/70"
              )}
              aria-label={`Go to image ${i + 1}`}
            />
          ))}
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useRef, useState } from "react";
import { motion, useMotionValue, useSpring, useMotionTemplate } from "framer-motion";
import { cn } from "@/lib/utils";

interface VideoRevealProps extends React.HTMLAttributes<HTMLDivElement> {
  videoSrc: string;
  posterSrc?: string;
  text?: string;
  variant?: "hover-zoom" | "cursor-mask" | "split-door";
}

export function VideoReveal({
  className,
  videoSrc,
  posterSrc,
  text = "Hover to Reveal",
  variant = "hover-zoom",
  ...props
}: VideoRevealProps) {
  const [isHovered, setIsHovered] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);

  // For cursor-mask variant
  const mouseX = useMotionValue(0);
  const mouseY = useMotionValue(0);

  // Smooth out the mouse movement for the mask
  const smoothX = useSpring(mouseX, { stiffness: 300, damping: 25 });
  const smoothY = useSpring(mouseY, { stiffness: 300, damping: 25 });
  const maskSize = useSpring(0, { stiffness: 300, damping: 25 });

  const clipPath = useMotionTemplate`circle(${maskSize}px at ${smoothX}px ${smoothY}px)`;

  const handleMouseEnter = () => {
    setIsHovered(true);
    if (variant === "cursor-mask") maskSize.set(200);
    if (videoRef.current) {
      videoRef.current.play().catch(() => {});
    }
  };

  const handleMouseLeave = () => {
    setIsHovered(false);
    if (variant === "cursor-mask") maskSize.set(0);
    if (videoRef.current) {
      videoRef.current.pause();
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (variant === "cursor-mask" && containerRef.current) {
      const rect = containerRef.current.getBoundingClientRect();
      mouseX.set(e.clientX - rect.left);
      mouseY.set(e.clientY - rect.top);
    }
  };

  return (
    <div
      ref={containerRef}
      className={cn(
        "relative w-full aspect-[16/9] overflow-hidden rounded-2xl bg-zinc-950 group cursor-crosshair border border-white/5",
        className
      )}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      onMouseMove={handleMouseMove}
      {...props}
    >
      {/* ─── Static Foreground Text (Visible when video is hidden) ─── */}
      <div className="absolute inset-0 flex items-center justify-center z-10 pointer-events-none mix-blend-difference">
        <h3 className="text-3xl md:text-5xl font-black text-white tracking-tighter uppercase">
          {text}
        </h3>
      </div>

      {/* ─── Variant: Hover Zoom ─── */}
      {variant === "hover-zoom" && (
        <motion.div
          className="absolute inset-0 origin-center"
          initial={{ scale: 0.8, opacity: 0 }}
          animate={{
            scale: isHovered ? 1 : 0.85,
            opacity: isHovered ? 1 : 0,
            filter: isHovered ? "blur(0px)" : "blur(10px)",
          }}
          transition={{ duration: 0.6, ease: [0.16, 1, 0.3, 1] }}
        >
          <video
            ref={videoRef}
            className="w-full h-full object-cover"
            src={videoSrc}
            poster={posterSrc}
            muted
            loop
            playsInline
          />
          <div className="absolute inset-0 bg-black/20" />
        </motion.div>
      )}

      {/* ─── Variant: Cursor Mask ─── */}
      {variant === "cursor-mask" && (
        <motion.div
          className="absolute inset-0 z-0"
          style={{ clipPath }}
        >
          <video
            ref={videoRef}
            className="w-full h-full object-cover"
            src={videoSrc}
            poster={posterSrc}
            muted
            loop
            playsInline
          />
          <div className="absolute inset-0 bg-black/10" />
        </motion.div>
      )}

      {/* ─── Variant: Split Door ─── */}
      {variant === "split-door" && (
        <>
          <div className="absolute inset-0 z-0">
            <video
              ref={videoRef}
              className="w-full h-full object-cover"
              src={videoSrc}
              poster={posterSrc}
              muted
              loop
              playsInline
            />
            <div className="absolute inset-0 bg-black/20" />
          </div>

          {/* Top Door */}
          <motion.div
            className="absolute top-0 left-0 right-0 h-1/2 bg-zinc-900 border-b border-white/5 z-10 pointer-events-none"
            initial={{ y: 0 }}
            animate={{ y: isHovered ? "-100%" : 0 }}
            transition={{ duration: 0.6, ease: [0.22, 1, 0.36, 1] }}
          />
          {/* Bottom Door */}
          <motion.div
            className="absolute bottom-0 left-0 right-0 h-1/2 bg-zinc-900 border-t border-white/5 z-10 pointer-events-none"
            initial={{ y: 0 }}
            animate={{ y: isHovered ? "100%" : 0 }}
            transition={{ duration: 0.6, ease: [0.22, 1, 0.36, 1] }}
          />
        </>
      )}
    </div>
  );
}

"use client";

import React, { useRef, useState, useEffect } from "react";
import { Play, Pause } from "lucide-react";
import { cn } from "@/lib/utils";

export interface AudioVisualizerProps {
  audioUrl: string;
  color?: string;
  className?: string;
}

export function AudioVisualizer({
  audioUrl,
  color = "#a855f7",
  className,
}: AudioVisualizerProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const audioRef = useRef<HTMLAudioElement>(null);
  const audioCtxRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const sourceRef = useRef<MediaElementAudioSourceNode | null>(null);
  const rafIdRef = useRef<number>(0);

  const [isPlaying, setIsPlaying] = useState(false);
  const [isReady, setIsReady] = useState(false);

  // Initialize Web Audio API
  const initAudio = () => {
    if (!audioRef.current || audioCtxRef.current) return;

    // Create audio context
    const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
    const ctx = new AudioContextClass();
    audioCtxRef.current = ctx;

    const analyser = ctx.createAnalyser();
    analyser.fftSize = 256;
    analyserRef.current = analyser;

    // Connect audio element to analyser
    const source = ctx.createMediaElementSource(audioRef.current);
    source.connect(analyser);
    analyser.connect(ctx.destination);
    sourceRef.current = source;
  };

  const togglePlay = () => {
    if (!audioRef.current) return;

    if (!audioCtxRef.current) {
      initAudio();
    }

    if (audioCtxRef.current?.state === "suspended") {
      audioCtxRef.current.resume();
    }

    if (isPlaying) {
      audioRef.current.pause();
    } else {
      audioRef.current.play().catch(e => console.error("Audio play failed:", e));
    }

    setIsPlaying(!isPlaying);
  };

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    const onEnded = () => setIsPlaying(false);
    const onCanPlay = () => setIsReady(true);

    audio.addEventListener('ended', onEnded);
    audio.addEventListener('canplaythrough', onCanPlay);

    return () => {
      audio.removeEventListener('ended', onEnded);
      audio.removeEventListener('canplaythrough', onCanPlay);
    };
  }, []);

  useEffect(() => {
    if (!canvasRef.current) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    // Handle high-DPI displays
    const dpr = window.devicePixelRatio || 1;
    const rect = canvas.getBoundingClientRect();
    canvas.width = rect.width * dpr;
    canvas.height = rect.height * dpr;
    ctx.scale(dpr, dpr);

    const draw = () => {
      if (!canvasRef.current || !ctx) return;

      const width = rect.width;
      const height = rect.height;
      const centerX = width / 2;
      const centerY = height / 2;

      // Clear canvas
      ctx.clearRect(0, 0, width, height);

      let dataArray = new Uint8Array(0);
      if (analyserRef.current && isPlaying) {
        dataArray = new Uint8Array(analyserRef.current.frequencyBinCount);
        analyserRef.current.getByteFrequencyData(dataArray);
      }

      // Draw Circular Visualizer
      const radius = Math.min(width, height) / 4;
      const barCount = 64; // How many bars to draw around the circle
      const maxBarHeight = radius * 0.8;

      for (let i = 0; i < barCount; i++) {
        // Map frequency data if available, otherwise just draw a flat circle
        let value = 0;
        if (dataArray.length > 0) {
          // Map the 64 bars to the lower half of the 128 frequency bins for more action
          value = dataArray[i]; 
        }

        const percent = value / 255;
        // Add a tiny baseline height so it's a visible circle even when quiet
        const barHeight = Math.max(percent * maxBarHeight, 2); 

        // Distribute evenly around a circle
        const angle = (i / barCount) * Math.PI * 2 - Math.PI / 2;

        const x1 = centerX + Math.cos(angle) * radius;
        const y1 = centerY + Math.sin(angle) * radius;
        const x2 = centerX + Math.cos(angle) * (radius + barHeight);
        const y2 = centerY + Math.sin(angle) * (radius + barHeight);

        ctx.beginPath();
        ctx.moveTo(x1, y1);
        ctx.lineTo(x2, y2);
        ctx.lineWidth = 4;
        ctx.lineCap = "round";

        // Create glowing stroke
        ctx.strokeStyle = color;
        ctx.shadowBlur = 15;
        ctx.shadowColor = color;
        ctx.stroke();
      }

      // Draw center play button circle (static)
      ctx.beginPath();
      ctx.arc(centerX, centerY, radius - 15, 0, Math.PI * 2);
      ctx.fillStyle = "rgba(0,0,0,0.5)";
      ctx.shadowBlur = 0;
      ctx.fill();

      rafIdRef.current = requestAnimationFrame(draw);
    };

    draw();

    return () => {
      cancelAnimationFrame(rafIdRef.current);
    };
  }, [isPlaying, color]);

  return (
    <div className={cn("relative w-full aspect-square max-w-md mx-auto", className)}>
      <audio 
        ref={audioRef} 
        src={audioUrl} 
        crossOrigin="anonymous" 
        preload="auto"
      />

      <canvas 
        ref={canvasRef} 
        className="w-full h-full"
        style={{ touchAction: "none" }}
      />

      <button
        onClick={togglePlay}
        className="absolute inset-0 m-auto w-16 h-16 rounded-full flex items-center justify-center bg-white/10 hover:bg-white/20 backdrop-blur-md border border-white/20 text-white transition-all hover:scale-110 active:scale-95 z-10"
      >
        {isPlaying ? (
          <Pause className="w-6 h-6" />
        ) : (
          <Play className="w-6 h-6 ml-1" />
        )}
      </button>
    </div>
  );
}

