import React, { useState } from "react";
import { motion, AnimatePresence, PanInfo } from "framer-motion";
import { cn } from "@/lib/utils";

export type CardStackVariant = "bottom" | "top" | "left" | "fan";

export interface Card {
  id: string | number;
  content: React.ReactNode;
}

interface CardStackProps {
  items: Card[];
  /** Distance between cards. Default: 10 */
  offset?: number;
  /** How much each successive card scales down. Default: 0.05 */
  scaleFactor?: number;
  className?: string;
  /** Layout and interaction style. Default: "bottom" */
  variant?: CardStackVariant;
}

export function CardStack({
  items,
  offset = 12,
  scaleFactor = 0.06,
  className,
  variant = "bottom",
}: CardStackProps) {
  const [cards, setCards] = useState<Card[]>(items);
  const [draggedCard, setDraggedCard] = useState<string | number | null>(null);

  const moveToEnd = (id: string | number) => {
    setCards((prev) => {
      const idx = prev.findIndex((c) => c.id === id);
      if (idx === -1) return prev;
      const newCards = [...prev];
      const [card] = newCards.splice(idx, 1);
      newCards.push(card);
      return newCards;
    });
  };

  const handleDragEnd = (event: any, info: PanInfo, id: string | number) => {
    const threshold = 100;
    if (Math.abs(info.offset.x) > threshold || Math.abs(info.offset.y) > threshold) {
      moveToEnd(id);
    }
    setDraggedCard(null);
  };

  const getCardStyles = (index: number, isDragged: boolean) => {
    if (isDragged) {
      return {
        top: 0,
        left: 0,
        scale: 1,
        rotate: 0,
      };
    }

    const scale = 1 - index * scaleFactor;

    switch (variant) {
      case "top":
        return { top: -index * offset, left: 0, scale, rotate: 0 };
      case "left":
        return { top: 0, left: -index * offset, scale, rotate: 0 };
      case "fan":
        return { 
          top: index * (offset / 2), 
          left: 0, 
          scale, 
          rotate: index % 2 === 0 ? index * 4 : -index * 4 
        };
      case "bottom":
      default:
        return { top: index * offset, left: 0, scale, rotate: 0 };
    }
  };

  return (
    <div className={cn("relative flex items-center justify-center h-full w-full", className)}>
      <AnimatePresence>
        {cards.map((card, index) => {
          const isTop = index === 0;
          const isDragged = draggedCard === card.id;

          // Only show top 3 cards for performance and visual clarity
          if (index > 3) return null;

          const activeStyle = getCardStyles(index, isDragged);

          return (
            <motion.div
              key={card.id}
              layout
              role={isTop ? "button" : "presentation"}
              tabIndex={isTop ? 0 : -1}
              aria-label={isTop ? "Swipeable card. Press Enter or Space to send to back." : undefined}
              onKeyDown={(e) => {
                if (isTop && (e.key === "Enter" || e.key === " ")) {
                  e.preventDefault();
                  moveToEnd(card.id);
                }
              }}
              className={cn(
                "absolute origin-center flex items-center justify-center",
                isTop ? "cursor-grab active:cursor-grabbing z-50" : "cursor-default",
              )}
              style={{
                zIndex: cards.length - index,
              }}
              drag={isTop}
              dragConstraints={{ left: 0, right: 0, top: 0, bottom: 0 }}
              dragElastic={0.5}
              onDragStart={() => setDraggedCard(card.id)}
              onDragEnd={(e, info) => handleDragEnd(e, info, card.id)}
              initial={{
                ...activeStyle,
                opacity: 0,
              }}
              animate={{
                ...activeStyle,
                opacity: 1,
              }}
              exit={{
                opacity: 0,
                scale: 0.5,
              }}
              transition={{
                type: "spring",
                stiffness: 300,
                damping: 20,
              }}
            >
              {card.content}
            </motion.div>
          );
        })}
      </AnimatePresence>
    </div>
  );
}

"use client";

import React, { useRef, useEffect } from "react";
import { motion, useMotionValue, useSpring, useTransform } from "framer-motion";
import { cn } from "@/lib/utils";

interface MagneticImageProps {
  src: string;
  alt: string;
  mouseX: any;
  mouseY: any;
  className?: string;
}

function MagneticImage({ src, alt, mouseX, mouseY, className }: MagneticImageProps) {
  const ref = useRef<HTMLDivElement>(null);

  // Local state for the center of this specific image
  const centerX = useMotionValue(0);
  const centerY = useMotionValue(0);

  useEffect(() => {
    const updateCenter = () => {
      if (ref.current) {
        const rect = ref.current.getBoundingClientRect();
        // Calculate center relative to the viewport
        centerX.set(rect.left + rect.width / 2);
        centerY.set(rect.top + rect.height / 2);
      }
    };

    updateCenter();
    window.addEventListener("resize", updateCenter);
    window.addEventListener("scroll", updateCenter);
    return () => {
      window.removeEventListener("resize", updateCenter);
      window.removeEventListener("scroll", updateCenter);
    };
  }, [centerX, centerY]);

  // Calculate distance from mouse to the center of this image
  // We use useTransform to create a derived value that updates every frame
  const distanceX = useTransform(() => mouseX.get() - centerX.get());
  const distanceY = useTransform(() => mouseY.get() - centerY.get());

  // Convert distance into a rotation angle.
  // The further away the mouse is, the less it rotates.
  // We clamp the rotation to a max of 20 degrees.
  const rotateX = useTransform(distanceY, [-500, 0, 500], [20, 0, -20]);
  const rotateY = useTransform(distanceX, [-500, 0, 500], [-20, 0, 20]);

  // Also scale slightly if the mouse is close
  const distance = useTransform(() => {
    const dx = distanceX.get();
    const dy = distanceY.get();
    return Math.sqrt(dx * dx + dy * dy);
  });

  const scale = useTransform(distance, [0, 500], [1.1, 1]);

  return (
    <motion.div
      ref={ref}
      style={{
        rotateX,
        rotateY,
        scale,
        transformPerspective: 1000,
      }}
      className={cn("relative overflow-hidden rounded-xl shadow-2xl bg-zinc-900", className)}
    >
      <img src={src} alt={alt} className="w-full h-full object-cover" />
    </motion.div>
  );
}

interface MagneticGalleryProps extends React.HTMLAttributes<HTMLDivElement> {
  images: { src: string; alt: string; className?: string }[];
}

export function MagneticGallery({ images, className, ...props }: MagneticGalleryProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  const mouseX = useMotionValue(-1000); // Initialize off-screen
  const mouseY = useMotionValue(-1000);

  // Smooth out the global mouse movement
  const smoothMouseX = useSpring(mouseX, { stiffness: 150, damping: 20 });
  const smoothMouseY = useSpring(mouseY, { stiffness: 150, damping: 20 });

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      mouseX.set(e.clientX);
      mouseY.set(e.clientY);
    };

    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, [mouseX, mouseY]);

  return (
    <div className="@container w-full">
      <div
        ref={containerRef}
        className={cn("grid grid-cols-1 @md:grid-cols-2 @lg:grid-cols-3 gap-6 p-4 @md:p-8", className)}
        style={{ perspective: "1200px" }}
        {...props}
      >
        {images.map((image, i) => (
          <MagneticImage
            key={i}
            src={image.src}
            alt={image.alt}
            mouseX={smoothMouseX}
            mouseY={smoothMouseY}
            className={cn("h-48 @md:h-64", image.className)}
          />
        ))}
      </div>
    </div>
  );
}

"use client";

import React, { createContext, useContext, useEffect, useRef, useState, useLayoutEffect } from "react";
import Matter from "matter-js";
import { cn } from "@/lib/utils";

// ─── CONTEXT ───

interface PhysicsContextType {
  engine: Matter.Engine | null;
  world: Matter.World | null;
}

const PhysicsContext = createContext<PhysicsContextType>({ engine: null, world: null });

// ─── PHYSICS CANVAS (WRAPPER) ───

export interface PhysicsCanvasProps extends React.HTMLAttributes<HTMLDivElement> {
  children: React.ReactNode;
  /** Background color or Tailwind classes */
  className?: string;
  /** Friction of the air/environment (0 to 1) */
  frictionAir?: number;
  /** Gravity multiplier */
  gravity?: { x: number; y: number };
}

export function PhysicsCanvas({
  children,
  className,
  frictionAir = 0.02,
  gravity = { x: 0, y: 1 },
  ...props
}: PhysicsCanvasProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  const [engineState, setEngineState] = useState<PhysicsContextType>({ engine: null, world: null });
  const mouseConstraintRef = useRef<Matter.MouseConstraint | null>(null);
  const wallsRef = useRef<Matter.Body[]>([]);

  // Initialize Matter.js Engine
  useEffect(() => {
    if (!containerRef.current) return;

    // Create Engine
    const engine = Matter.Engine.create({
      gravity: {
        x: gravity.x,
        y: gravity.y,
        scale: 0.001,
      },
      positionIterations: 6,
      velocityIterations: 4,
    });
    const world = engine.world;

    // Create Mouse and MouseConstraint for dragging
    const mouse = Matter.Mouse.create(containerRef.current);
    const mouseConstraint = Matter.MouseConstraint.create(engine, {
      mouse: mouse,
      constraint: {
        stiffness: 0.2,
        render: {
          visible: false,
        },
      },
    });
    mouseConstraintRef.current = mouseConstraint;

    // Keep the mouse in sync with scrolling
    Matter.Events.on(engine, "beforeUpdate", () => {
      Matter.Mouse.setScale(mouse, { x: 1, y: 1 });
    });

    Matter.World.add(world, mouseConstraint);

    // Initial Walls
    const wallOptions = { isStatic: true, friction: 0, restitution: 0.5 };
    const w = containerRef.current.clientWidth;
    const h = containerRef.current.clientHeight;
    const thickness = 500; // Thick walls prevent tunneling

    wallsRef.current = [
      Matter.Bodies.rectangle(w / 2, -thickness / 2, w + thickness * 2, thickness, wallOptions), // Top
      Matter.Bodies.rectangle(w / 2, h + thickness / 2, w + thickness * 2, thickness, wallOptions), // Bottom
      Matter.Bodies.rectangle(-thickness / 2, h / 2, thickness, h + thickness * 2, wallOptions), // Left
      Matter.Bodies.rectangle(w + thickness / 2, h / 2, thickness, h + thickness * 2, wallOptions), // Right
    ];
    Matter.World.add(world, wallsRef.current);

    // Start Runner
    const runner = Matter.Runner.create();
    Matter.Runner.run(runner, engine);

    setEngineState({ engine, world });

    // Handle Resizing
    const handleResize = () => {
      if (!containerRef.current) return;
      const width = containerRef.current.clientWidth;
      const height = containerRef.current.clientHeight;

      // Update wall positions and sizes
      Matter.Body.setPosition(wallsRef.current[0], { x: width / 2, y: -thickness / 2 });
      Matter.Body.setPosition(wallsRef.current[1], { x: width / 2, y: height + thickness / 2 });
      Matter.Body.setPosition(wallsRef.current[2], { x: -thickness / 2, y: height / 2 });
      Matter.Body.setPosition(wallsRef.current[3], { x: width + thickness / 2, y: height / 2 });

      // Note: Changing dimensions of bodies dynamically in Matter.js requires recreating them or scaling.
      // Scaling static walls is perfectly fine for basic boundaries.
    };

    const resizeObserver = new ResizeObserver(handleResize);
    resizeObserver.observe(containerRef.current);

    // Cleanup
    return () => {
      Matter.Runner.stop(runner);
      Matter.Engine.clear(engine);
      resizeObserver.disconnect();
    };
  }, [gravity.x, gravity.y]);

  return (
    <PhysicsContext.Provider value={engineState}>
      <div 
        ref={containerRef} 
        className={cn("relative overflow-hidden", className)} 
        {...props}
      >
        {children}
      </div>
    </PhysicsContext.Provider>
  );
}

// ─── PHYSICS ITEM (CHILD) ───

export interface PhysicsItemProps extends React.HTMLAttributes<HTMLDivElement> {
  children: React.ReactNode;
  /** Initial X position */
  x: number;
  /** Initial Y position */
  y: number;
  /** Width in pixels */
  width: number;
  /** Height in pixels */
  height: number;
  /** Body shape (default rectangle) */
  shape?: "rectangle" | "circle";
  /** Bounciness (0 to 1) */
  restitution?: number;
  /** Friction (0 to 1) */
  friction?: number;
  /** Density (mass = density * area) */
  density?: number;
  className?: string;
}

export function PhysicsItem({
  children,
  x,
  y,
  width,
  height,
  shape = "rectangle",
  restitution = 0.5,
  friction = 0.1,
  density = 0.001,
  className,
  ...props
}: PhysicsItemProps) {
  const { engine, world } = useContext(PhysicsContext);
  const elementRef = useRef<HTMLDivElement>(null);
  const bodyRef = useRef<Matter.Body | null>(null);

  useLayoutEffect(() => {
    if (!engine || !world || !elementRef.current) return;

    // Create the body
    let body: Matter.Body;
    const commonOptions = {
      restitution,
      friction,
      density,
      frictionAir: 0.02,
      render: { visible: false } // We use DOM
    };

    if (shape === "circle") {
      const radius = Math.min(width, height) / 2;
      body = Matter.Bodies.circle(x, y, radius, commonOptions);
    } else {
      body = Matter.Bodies.rectangle(x, y, width, height, Object.assign({}, commonOptions, { chamfer: { radius: 8 } }));
    }

    bodyRef.current = body;
    Matter.World.add(world, body);

    // Sync DOM on engine update
    const updateElement = () => {
      if (elementRef.current && bodyRef.current) {
        const { position, angle } = bodyRef.current;
        // We use absolute positioning and CSS transform for 60fps performance
        elementRef.current.style.transform = `translate(-50%, -50%) translate(${position.x}px, ${position.y}px) rotate(${angle}rad)`;
      }
    };

    Matter.Events.on(engine, "afterUpdate", updateElement);

    return () => {
      Matter.Events.off(engine, "afterUpdate", updateElement);
      if (bodyRef.current) {
        Matter.World.remove(world, bodyRef.current);
      }
    };
  }, [engine, world, x, y, width, height, shape, restitution, friction, density]);

  return (
    <div
      ref={elementRef}
      className={cn("absolute top-0 left-0 cursor-grab active:cursor-grabbing", className)}
      style={{
        width,
        height,
        // The transform origin must be center because Matter.js positions are center-based
        transformOrigin: "center center", 
        // Set an initial position so it doesn't flicker at 0,0 before the first frame
        transform: `translate(-50%, -50%) translate(${x}px, ${y}px) rotate(0rad)`,
      }}
      {...props}
    >
      {children}
    </div>
  );
}

"use client";

import React, { useRef, useState, useCallback, useEffect } from "react";
import { cn } from "@/lib/utils";

export interface MinimapProps extends React.HTMLAttributes<HTMLDivElement> {
  /** The total width of the virtual canvas (in px) */
  canvasWidth: number;
  /** The total height of the virtual canvas (in px) */
  canvasHeight: number;
  /** The current scroll/pan offset X of the main viewport */
  viewportX: number;
  /** The current scroll/pan offset Y of the main viewport */
  viewportY: number;
  /** The visible width of the main viewport (container width) */
  viewportWidth: number;
  /** The visible height of the main viewport (container height) */
  viewportHeight: number;
  /** Callback when the user drags the viewport box inside the minimap */
  onViewportChange?: (x: number, y: number) => void;
  /** Width of the minimap widget in px */
  width?: number;
  /** Height of the minimap widget in px */
  height?: number;
  /** Items to render as dots/rectangles on the minimap */
  items?: { x: number; y: number; width: number; height: number; color?: string }[];
  /** Position of the minimap on screen */
  position?: "bottom-right" | "bottom-left" | "top-right" | "top-left";
}

export function Minimap({
  canvasWidth,
  canvasHeight,
  viewportX,
  viewportY,
  viewportWidth,
  viewportHeight,
  onViewportChange,
  width = 200,
  height = 150,
  items = [],
  position = "bottom-right",
  className,
  ...props
}: MinimapProps) {
  const minimapRef = useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = useState(false);

  // Scale factors: how many canvas pixels map to 1 minimap pixel
  const scaleX = width / canvasWidth;
  const scaleY = height / canvasHeight;

  // Viewport rectangle dimensions on the minimap
  const vpW = viewportWidth * scaleX;
  const vpH = viewportHeight * scaleY;
  const vpX = viewportX * scaleX;
  const vpY = viewportY * scaleY;

  // Convert a minimap click/drag position to canvas coordinates
  const minimapToCanvas = useCallback(
    (clientX: number, clientY: number) => {
      if (!minimapRef.current) return;
      const rect = minimapRef.current.getBoundingClientRect();
      const mx = clientX - rect.left;
      const my = clientY - rect.top;

      // Center the viewport on the click point
      const canvasX = mx / scaleX - viewportWidth / 2;
      const canvasY = my / scaleY - viewportHeight / 2;

      // Clamp to canvas bounds
      const clampedX = Math.max(0, Math.min(canvasWidth - viewportWidth, canvasX));
      const clampedY = Math.max(0, Math.min(canvasHeight - viewportHeight, canvasY));

      onViewportChange?.(clampedX, clampedY);
    },
    [scaleX, scaleY, viewportWidth, viewportHeight, canvasWidth, canvasHeight, onViewportChange]
  );

  const handleMouseDown = (e: React.MouseEvent) => {
    e.preventDefault();
    setIsDragging(true);
    minimapToCanvas(e.clientX, e.clientY);
  };

  useEffect(() => {
    if (!isDragging) return;

    const handleMouseMove = (e: MouseEvent) => {
      minimapToCanvas(e.clientX, e.clientY);
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    window.addEventListener("mousemove", handleMouseMove);
    window.addEventListener("mouseup", handleMouseUp);

    return () => {
      window.removeEventListener("mousemove", handleMouseMove);
      window.removeEventListener("mouseup", handleMouseUp);
    };
  }, [isDragging, minimapToCanvas]);

  const positionClasses = {
    "bottom-right": "bottom-4 right-4",
    "bottom-left": "bottom-4 left-4",
    "top-right": "top-4 right-4",
    "top-left": "top-4 left-4",
  };

  return (
    <div
      ref={minimapRef}
      onMouseDown={handleMouseDown}
      className={cn(
        "absolute z-50 rounded-xl overflow-hidden border border-white/15 bg-zinc-950/80 backdrop-blur-xl shadow-2xl cursor-crosshair select-none",
        positionClasses[position],
        isDragging && "ring-2 ring-indigo-500/50",
        className
      )}
      style={{ width, height }}
      {...props}
    >
      {/* Grid lines for visual reference */}
      <svg
        className="absolute inset-0 w-full h-full pointer-events-none opacity-20"
        viewBox={`0 0 ${width} ${height}`}
      >
        {/* Vertical grid lines */}
        {Array.from({ length: 5 }).map((_, i) => (
          <line
            key={`v-${i}`}
            x1={(width / 5) * (i + 1)}
            y1={0}
            x2={(width / 5) * (i + 1)}
            y2={height}
            stroke="white"
            strokeWidth={0.5}
          />
        ))}
        {/* Horizontal grid lines */}
        {Array.from({ length: 4 }).map((_, i) => (
          <line
            key={`h-${i}`}
            x1={0}
            y1={(height / 4) * (i + 1)}
            x2={width}
            y2={(height / 4) * (i + 1)}
            stroke="white"
            strokeWidth={0.5}
          />
        ))}
      </svg>

      {/* Render items as colored rectangles */}
      {items.map((item, i) => (
        <div
          key={i}
          className="absolute rounded-sm pointer-events-none"
          style={{
            left: item.x * scaleX,
            top: item.y * scaleY,
            width: Math.max(item.width * scaleX, 3),
            height: Math.max(item.height * scaleY, 3),
            backgroundColor: item.color || "rgba(99, 102, 241, 0.6)",
          }}
        />
      ))}

      {/* Viewport indicator */}
      <div
        className="absolute rounded-md border-2 border-white/60 bg-white/5 transition-[left,top] duration-75 ease-out"
        style={{
          left: vpX,
          top: vpY,
          width: Math.max(vpW, 8),
          height: Math.max(vpH, 6),
        }}
      />

      {/* Minimap label */}
      <div className="absolute top-1.5 left-2 text-[9px] font-mono font-bold text-white/30 uppercase tracking-widest pointer-events-none">
        Minimap
      </div>
    </div>
  );
}

