import React, { Children } from "react";
import { cn } from "@/lib/utils";
import { motion, HTMLMotionProps, Variants } from "framer-motion";

export interface BrokenGridProps extends HTMLMotionProps<"div"> {
  children: React.ReactNode;
  columns?: number;
  gap?: number;
  animate?: boolean;
}

export function BrokenGrid({
  children,
  columns = 12,
  gap = 4,
  animate = true,
  className,
  ...props
}: BrokenGridProps) {
  const childrenArray = Children.toArray(children);

  const containerVariants: Variants = {
    hidden: { opacity: 0 },
    show: {
      opacity: 1,
      transition: { staggerChildren: 0.15 },
    },
  };

  const itemVariants: Variants = {
    hidden: { opacity: 0, y: 30, filter: "blur(5px)" },
    show: { 
      opacity: 1, 
      y: 0, 
      filter: "blur(0px)",
      transition: { type: "spring", stiffness: 200, damping: 20 } 
    },
  };

  return (
    <motion.div
      variants={animate ? containerVariants : undefined}
      initial={animate ? "hidden" : undefined}
      whileInView={animate ? "show" : undefined}
      viewport={{ once: true, margin: "-100px" }}
      className={cn(
        "grid",
        `grid-cols-${columns}`,
        `gap-${gap}`,
        className
      )}
      style={{
        gridTemplateColumns: `repeat(${columns}, minmax(0, 1fr))`,
      }}
      {...props}
    >
      {childrenArray.map((child, i) => {
        if (React.isValidElement(child)) {
          return animate ? React.cloneElement(child, { variants: itemVariants } as any) : child;
        }
        return child;
      })}
    </motion.div>
  );
}

export interface BrokenGridItemProps extends HTMLMotionProps<"div"> {
  children?: React.ReactNode;
  colSpan?: number | { sm?: number; md?: number; lg?: number };
  rowSpan?: number;
  colStart?: number | { sm?: number; md?: number; lg?: number };
  rowStart?: number;
  offsetX?: string;
  offsetY?: string;
  zIndex?: number;
}

export function BrokenGridItem({
  children,
  colSpan = 4,
  rowSpan = 1,
  colStart,
  rowStart,
  offsetX = "0px",
  offsetY = "0px",
  zIndex = 1,
  className,
  ...props
}: BrokenGridItemProps) {

  // Helper to generate col-span classes based on responsive object or number
  const getColSpanStyle = () => {
    if (typeof colSpan === 'number') return { gridColumnEnd: `span ${colSpan}` };
    return {
      gridColumnEnd: `span ${colSpan.lg || colSpan.md || colSpan.sm || 4}`
    }; // simplified for inline styles; in real world might need media queries if not using classes
  };

  const getColStartStyle = () => {
    if (!colStart) return {};
    if (typeof colStart === 'number') return { gridColumnStart: colStart };
    return {
      gridColumnStart: colStart.lg || colStart.md || colStart.sm || 1
    };
  };

  return (
    <motion.div
      className={cn("relative w-full h-full", className)}
      style={{
        ...getColSpanStyle(),
        ...getColStartStyle(),
        ...(rowSpan > 1 ? { gridRowEnd: `span ${rowSpan}` } : {}),
        ...(rowStart ? { gridRowStart: rowStart } : {}),
        transform: `translate(${offsetX}, ${offsetY})`,
        zIndex,
      }}
      {...props}
    >
      {children}
    </motion.div>
  );
}

"use client";

import React, { useRef, ReactNode } from "react";
import { motion, useScroll, useTransform } from "framer-motion";
import { cn } from "@/lib/utils";

interface ParallaxFooterProps extends React.HTMLAttributes<HTMLDivElement> {
  children: ReactNode;
  scrollContainer?: React.RefObject<any>;
  /** Parallax intensity — higher = more travel. Default: 30 */
  intensity?: number;
  /** Show the large watermark brand text behind the footer */
  watermark?: string;
  /** Gradient accent color (CSS color string) */
  accentColor?: string;
}

export function ParallaxFooter({
  children,
  className,
  scrollContainer,
  intensity = 30,
  watermark,
  accentColor = "#6366f1",
  ...props
}: ParallaxFooterProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  const { scrollYProgress } = useScroll({
    target: containerRef,
    container: scrollContainer,
    offset: ["start end", "end end"],
  });

  // Parallax effect: slides up into view
  const y = useTransform(scrollYProgress, [0, 1], [`-${intensity}%`, "0%"]);
  // Slight scale for depth
  const scale = useTransform(scrollYProgress, [0, 1], [0.97, 1]);
  // Fade-in on scroll — start partially visible so content isn't hidden in embedded containers
  const opacity = useTransform(scrollYProgress, [0, 0.5], [0.3, 1]);

  return (
    <footer
      ref={containerRef}
      className={cn("@container relative w-full overflow-hidden", className)}
      {...props}
    >
      {/* Ambient top glow */}
      <div
        className="pointer-events-none absolute -top-px left-0 right-0 h-px"
        style={{
          background: `linear-gradient(90deg, transparent, ${accentColor}, transparent)`,
        }}
      />
      <div
        className="pointer-events-none absolute -top-40 left-1/2 -translate-x-1/2 w-[600px] h-40 rounded-full blur-[100px] opacity-20"
        style={{ backgroundColor: accentColor }}
      />

      <motion.div style={{ y, scale, opacity }} className="relative w-full h-full">
        {/* Watermark brand text */}
        {watermark && (
          <div className="pointer-events-none absolute inset-0 flex items-end justify-center overflow-hidden pb-4">
            <span
              className="text-[18cqw] @md:text-[14cqw] font-black tracking-tighter leading-none select-none whitespace-nowrap"
              style={{
                color: "transparent",
                WebkitTextStroke: `1px rgba(255,255,255,0.04)`,
              }}
            >
              {watermark}
            </span>
          </div>
        )}

        {/* Noise texture */}
        <div className="pointer-events-none absolute inset-0 opacity-[0.03] bg-[url('data:image/svg+xml;base64,')] bg-repeat" />

        <div className="relative z-10 w-full h-full">{children}</div>
      </motion.div>
    </footer>
  );
}

