import React, { useRef } from "react";
import { motion, useScroll, useTransform } from "framer-motion";
import { cn } from "@/lib/utils";

interface TextMaskVideoRevealProps {
  text: string;
  videoSrc: string;
  className?: string;
  maskScaleFactor?: number;
}

export function TextMaskVideoReveal({
  text,
  videoSrc,
  className,
  maskScaleFactor = 60,
}: TextMaskVideoRevealProps) {
  const containerRef = useRef<HTMLDivElement>(null);

  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start start", "end end"]
  });

  // Scale the mask hole massively so the video fills the screen.
  // We use exponential scaling for a smoother 'fly-through' effect.
  const scale = useTransform(scrollYProgress, [0, 0.4, 0.8, 1], [1, 5, 20, maskScaleFactor]);

  // Fade out the mask completely at the very end to reveal the pure video
  const opacity = useTransform(scrollYProgress, [0.8, 1], [1, 0]);

  return (
    <div ref={containerRef} className={cn("relative h-[300vh]", className)}>
      <div className="sticky top-0 h-screen w-full overflow-hidden flex items-center justify-center bg-black">

        {/* Background Video */}
        <video 
          src={videoSrc}
          autoPlay 
          loop 
          muted 
          playsInline
          className="absolute inset-0 w-full h-full object-cover z-0"
        />

        {/* Text Mask Layer */}
        {/* We use mix-blend-multiply. Black stays black, White becomes transparent (showing the video). */}
        <motion.div 
          className="absolute inset-0 z-10 flex items-center justify-center bg-black mix-blend-multiply origin-center"
          style={{ scale, opacity }}
        >
          <h1 className="text-[20vw] md:text-[25vw] font-black text-white tracking-tighter text-center leading-none">
            {text}
          </h1>
        </motion.div>

      </div>
    </div>
  );
}

"use client";

import React, { useRef, useState, useMemo, useEffect, Suspense } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import { useTexture } from "@react-three/drei";
import * as THREE from "three";
import { cn } from "@/lib/utils";

const vertexShader = `
varying vec2 vUv;
void main() {
  vUv = uv;
  gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
}
`;

const fragmentShader = `
uniform sampler2D uTexture1;
uniform sampler2D uTexture2;
uniform float uProgress;
uniform float uTime;
varying vec2 vUv;

void main() {
  vec2 uv = vUv;

  // Intense liquid distortion wave based on time and progress
  float waveX = sin(uv.y * 15.0 + uTime * 2.0) * 0.05 * sin(uProgress * 3.1415);
  float waveY = cos(uv.x * 15.0 + uTime * 2.0) * 0.05 * sin(uProgress * 3.1415);

  vec2 distortedUv = uv + vec2(waveX, waveY);

  vec4 color1 = texture2D(uTexture1, distortedUv);
  vec4 color2 = texture2D(uTexture2, distortedUv);

  // Add a glitch color separation effect during the transition
  vec4 finalColor = mix(color1, color2, uProgress);

  // Vignette
  float dist = distance(uv, vec2(0.5));
  finalColor.rgb *= smoothstep(0.8, 0.2, dist);

  gl_FragColor = finalColor;
}
`;

function FluidScene({ images, currentIndex }: { images: string[], currentIndex: number }) {
  const textures = useTexture(images);
  const materialRef = useRef<THREE.ShaderMaterial>(null);

  // We keep track of the "from" and "to" indices to manage the transition shader
  const [prevIndex, setPrevIndex] = useState(currentIndex);

  useEffect(() => {
    if (currentIndex !== prevIndex) {
      if (materialRef.current) {
        // Reset progress to 0 and set the new textures
        materialRef.current.uniforms.uTexture1.value = textures[prevIndex];
        materialRef.current.uniforms.uTexture2.value = textures[currentIndex];
        materialRef.current.uniforms.uTargetProgress.value = 1.0;
        materialRef.current.uniforms.uProgress.value = 0.0;
      }
      // Update prevIndex after a short delay so the transition can happen
      const timer = setTimeout(() => setPrevIndex(currentIndex), 1000);
      return () => clearTimeout(timer);
    }
  }, [currentIndex, prevIndex, textures]);

  const uniforms = useMemo(() => ({
    uTexture1: { value: textures[prevIndex] },
    uTexture2: { value: textures[currentIndex] },
    uProgress: { value: 0 },
    uTargetProgress: { value: 0 },
    uTime: { value: 0 }
  }), [textures, prevIndex, currentIndex]);

  useFrame((state) => {
    if (materialRef.current) {
      // Smoothly interpolate progress
      materialRef.current.uniforms.uProgress.value = THREE.MathUtils.lerp(
        materialRef.current.uniforms.uProgress.value,
        materialRef.current.uniforms.uTargetProgress.value,
        0.05
      );
      materialRef.current.uniforms.uTime.value = state.clock.elapsedTime;
    }
  });

  // Calculate plane dimensions to cover viewport
  // Use a large plane to cover screen
  return (
    <mesh>
      <planeGeometry args={[16, 9]} />
      <shaderMaterial
        ref={materialRef}
        vertexShader={vertexShader}
        fragmentShader={fragmentShader}
        uniforms={uniforms}
      />
    </mesh>
  );
}

export interface FluidDistortionGalleryProps {
  images: string[];
  className?: string;
}

export function FluidDistortionGallery({ images, className }: FluidDistortionGalleryProps) {
  const [index, setIndex] = useState(0);

  const next = () => setIndex((i) => (i + 1) % images.length);
  const prev = () => setIndex((i) => (i - 1 + images.length) % images.length);

  return (
    <div className={cn("relative w-full h-[600px] overflow-hidden rounded-2xl bg-black cursor-pointer group", className)} onClick={next}>
      <Suspense fallback={<div className="absolute inset-0 flex items-center justify-center text-white font-mono">LOADING TEXTURES...</div>}>
        <Canvas camera={{ position: [0, 0, 5], fov: 50 }}>
          <FluidScene images={images} currentIndex={index} />
        </Canvas>
      </Suspense>
      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex gap-4 opacity-0 group-hover:opacity-100 transition-opacity">
        <button onClick={(e) => { e.stopPropagation(); prev(); }} className="px-4 py-2 bg-white/10 backdrop-blur-md rounded-full text-white hover:bg-white/20 font-mono text-xs">PREV</button>
        <button onClick={(e) => { e.stopPropagation(); next(); }} className="px-4 py-2 bg-white/10 backdrop-blur-md rounded-full text-white hover:bg-white/20 font-mono text-xs">NEXT</button>
      </div>
    </div>
  );
}

"use client";

import React, { useRef, useMemo } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import * as THREE from "three";
import { cn } from "@/lib/utils";

const vertexShader = `
uniform float uTime;
uniform vec3 uMouse;
attribute float size;

void main() {
  vec3 pos = position;

  // Interactive repulsion from mouse
  float dist = distance(pos, uMouse);
  if(dist < 3.0) {
    vec3 dir = normalize(pos - uMouse);
    // Exponential falloff for smooth repulsion
    pos += dir * (3.0 - dist) * 0.8;
  }

  // Ambient floating motion
  pos.y += sin(uTime * 0.5 + pos.x * 2.0) * 0.2;
  pos.x += cos(uTime * 0.5 + pos.y * 2.0) * 0.2;

  vec4 mvPosition = modelViewMatrix * vec4(pos, 1.0);

  // Perspective scaling for particle sizes
  gl_PointSize = size * (400.0 / -mvPosition.z);
  gl_Position = projectionMatrix * mvPosition;
}
`;

const fragmentShader = `
void main() {
  // Make particles perfectly circular
  vec2 xy = gl_PointCoord.xy - vec2(0.5);
  float ll = length(xy);
  if(ll > 0.5) discard;

  // Radial gradient for a soft, glowing orb effect
  float alpha = (0.5 - ll) * 2.0;

  // Cyberpunk cyan glow
  gl_FragColor = vec4(0.0, 1.0, 0.8, alpha);
}
`;

function Swarm({ count = 15000 }: { count?: number }) {
  const pointsRef = useRef<THREE.Points>(null);
  const materialRef = useRef<THREE.ShaderMaterial>(null);

  const [positions, sizes] = useMemo(() => {
    const positions = new Float32Array(count * 3);
    const sizes = new Float32Array(count);

    // Generate particles in a hollow sphere formation
    for (let i = 0; i < count; i++) {
      const radius = 6 + Math.random() * 2; // Radius between 6 and 8
      const theta = Math.random() * 2 * Math.PI;
      const phi = Math.acos((Math.random() * 2) - 1);

      positions[i * 3] = radius * Math.sin(phi) * Math.cos(theta);
      positions[i * 3 + 1] = radius * Math.sin(phi) * Math.sin(theta);
      positions[i * 3 + 2] = radius * Math.cos(phi);

      sizes[i] = Math.random() * 1.5; // Random initial sizes
    }

    return [positions, sizes];
  }, [count]);

  const uniforms = useMemo(() => ({
    uTime: { value: 0 },
    uMouse: { value: new THREE.Vector3(999, 999, 999) }
  }), []);

  useFrame((state) => {
    if (materialRef.current && pointsRef.current) {
      materialRef.current.uniforms.uTime.value = state.clock.elapsedTime;

      // Map screen mouse coordinates to 3D world space
      const { mouse, camera } = state;
      const vector = new THREE.Vector3(mouse.x, mouse.y, 0.5);
      vector.unproject(camera);
      const dir = vector.sub(camera.position).normalize();
      const distance = -camera.position.z / dir.z;
      const pos = camera.position.clone().add(dir.multiplyScalar(distance));

      // Smoothly interpolate the repulsion center towards the mouse
      materialRef.current.uniforms.uMouse.value.lerp(pos, 0.1);

      // Slowly rotate the entire swarm
      pointsRef.current.rotation.y = state.clock.elapsedTime * 0.1;
      pointsRef.current.rotation.x = state.clock.elapsedTime * 0.05;
    }
  });

  return (
    <points ref={pointsRef}>
      <bufferGeometry>
        <bufferAttribute attach="attributes-position" args={[positions, 3]} count={count} />
        <bufferAttribute attach="attributes-size" args={[sizes, 1]} count={count} />
      </bufferGeometry>
      <shaderMaterial
        ref={materialRef}
        vertexShader={vertexShader}
        fragmentShader={fragmentShader}
        uniforms={uniforms}
        transparent
        depthWrite={false}
        blending={THREE.AdditiveBlending}
      />
    </points>
  );
}

export interface InteractiveParticleSwarmProps {
  className?: string;
  particleCount?: number;
}

export function InteractiveParticleSwarm({ className, particleCount = 15000 }: InteractiveParticleSwarmProps) {
  return (
    <div className={cn("relative w-full h-[600px] bg-black overflow-hidden", className)}>
      {/* Fallback text while WebGL context initializes */}
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-0">
        <span className="text-cyan-900/30 font-mono text-xs tracking-[1em]">INITIALIZING_SWARM</span>
      </div>
      <Canvas camera={{ position: [0, 0, 15], fov: 60 }} className="z-10">
        <Swarm count={particleCount} />
      </Canvas>
    </div>
  );
}

"use client";

import React, { useRef, useState, useMemo } from "react";
import { Canvas, useFrame } from "@react-three/fiber";
import * as THREE from "three";
import { cn } from "@/lib/utils";
import { Play, Pause } from "lucide-react";

const vertexShader = `
uniform float uTime;
uniform float uAudioData;
varying vec3 vNormal;
varying vec3 vPosition;

void main() {
  vNormal = normal;
  vPosition = position;

  // 3D Noise function based on position and time
  float noise = sin(position.x * 4.0 + uTime) * sin(position.y * 4.0 + uTime) * sin(position.z * 4.0 + uTime);

  // Displace vertices along their normals based on audio volume and noise
  vec3 newPosition = position + normal * noise * (uAudioData * 1.5);

  gl_Position = projectionMatrix * modelViewMatrix * vec4(newPosition, 1.0);
}
`;

const fragmentShader = `
uniform float uTime;
uniform float uAudioData;
varying vec3 vNormal;
varying vec3 vPosition;

void main() {
  // Map normals to base color for iridescent effect
  vec3 baseColor = vec3(0.5) + 0.5 * vNormal;

  // Add a cyber-punk tint that reacts to audio intensity (Cyan to Magenta)
  vec3 tint = mix(vec3(0.0, 1.0, 0.8), vec3(1.0, 0.0, 0.8), uAudioData * 2.0);

  // Add fresnel rim lighting for depth
  float viewFactor = dot(normalize(vNormal), vec3(0.0, 0.0, 1.0));
  float rim = 1.0 - max(viewFactor, 0.0);
  rim = smoothstep(0.6, 1.0, rim);

  // Combine base color, tint, and a bright white rim flash on heavy bass beats
  vec3 finalColor = mix(baseColor * tint, vec3(1.0), rim * uAudioData);

  gl_FragColor = vec4(finalColor, 1.0);
}
`;

function VisualizerMesh({ analyserRef, dataArrayRef }: { analyserRef: any, dataArrayRef: any }) {
  const meshRef = useRef<THREE.Mesh>(null);
  const materialRef = useRef<THREE.ShaderMaterial>(null);

  const uniforms = useMemo(() => ({
    uTime: { value: 0 },
    uAudioData: { value: 0 }
  }), []);

  useFrame((state) => {
    if (materialRef.current) {
      materialRef.current.uniforms.uTime.value = state.clock.elapsedTime;

      let avgVolume = 0;
      if (analyserRef.current && dataArrayRef.current) {
        analyserRef.current.getByteFrequencyData(dataArrayRef.current);
        const sum = dataArrayRef.current.reduce((a: any, b: any) => a + b, 0);
        // Normalize volume (0.0 to 1.0)
        avgVolume = (sum / dataArrayRef.current.length) / 255;
      }

      // Smoothly interpolate the audio uniform to prevent jittering
      materialRef.current.uniforms.uAudioData.value = THREE.MathUtils.lerp(
        materialRef.current.uniforms.uAudioData.value,
        avgVolume,
        0.15
      );
    }

    if (meshRef.current) {
      meshRef.current.rotation.y += 0.005;
      meshRef.current.rotation.x += 0.002;
    }
  });

  return (
    <mesh ref={meshRef}>
      <icosahedronGeometry args={[2.5, 64]} />
      <shaderMaterial
        ref={materialRef}
        vertexShader={vertexShader}
        fragmentShader={fragmentShader}
        uniforms={uniforms}
        wireframe={true} // Render as a highly detailed wireframe mesh
        transparent
      />
    </mesh>
  );
}

export interface AudioReactiveVisualizerProps {
  audioSrc: string;
  className?: string;
}

export function AudioReactiveVisualizer({ audioSrc, className }: AudioReactiveVisualizerProps) {
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const dataArrayRef = useRef<Uint8Array | null>(null);
  const [audioInitialized, setAudioInitialized] = useState(false);

  const toggleAudio = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
      setIsPlaying(false);
    } else {
      if (!audioInitialized) {
        // Initialize Web Audio API context on first play to comply with browser auto-play policies
        const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
        const source = audioCtx.createMediaElementSource(audioRef.current);
        const analyser = audioCtx.createAnalyser();
        analyser.fftSize = 256;
        source.connect(analyser);
        analyser.connect(audioCtx.destination);

        analyserRef.current = analyser;
        dataArrayRef.current = new Uint8Array(analyser.frequencyBinCount);
        setAudioInitialized(true);
      }
      audioRef.current.play();
      setIsPlaying(true);
    }
  };

  return (
    <div className={cn("relative w-full h-[600px] bg-black rounded-2xl overflow-hidden group", className)}>
      <audio ref={audioRef} src={audioSrc} crossOrigin="anonymous" loop />

      <Canvas camera={{ position: [0, 0, 7], fov: 60 }} className="z-0">
        <VisualizerMesh analyserRef={analyserRef} dataArrayRef={dataArrayRef} />
      </Canvas>

      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-10">
        <button 
          onClick={toggleAudio}
          className="flex items-center gap-2 px-6 py-3 bg-white/10 hover:bg-white/20 backdrop-blur-md rounded-full text-white font-mono text-sm transition-all"
        >
          {isPlaying ? <Pause className="w-4 h-4" /> : <Play className="w-4 h-4" />}
          {isPlaying ? "PAUSE_TRACK" : "INIT_AUDIO"}
        </button>
      </div>
    </div>
  );
}

